# ─── Routes — Folders (Gmail-style project grouping) ──────────────────────────
#
# Lets the user organise projects under named folders. The folder is just a
# text label on `projects.folder` (added via ALTER TABLE in init_db). There is
# NO separate `folders` table — keep it simple. Empty string = un-grouped.
#
# Two views:
#   /folders          → list of distinct folders for the current user
#   /folder/<name>    → projects in that folder + per-report download links
#   /folder/<name>/zip.zip → bundles every available PDF report for every
#                            project in the folder into a single ZIP.
#
# The ZIP route uses Flask's in-process test_client so we can replay each
# existing /project/<pid>/report/<kind>/pdf route without duplicating the PDF
# generation logic. We forward the current session into the test client so
# @login_required + tenant filters pass.

import io
import re
import zipfile
from urllib.parse import unquote


def _safe_filename(name):
    # Strip filesystem-unsafe characters; keep reasonably short for ZIP entries.
    cleaned = re.sub(r"[^A-Za-z0-9._\- ]+", "_", (name or "untitled")).strip() or "untitled"
    return cleaned[:80]


# Reports the wizard produces. The two-tuple is (URL suffix, filename stub).
# We attempt every one; 4xx (plan-gated / no-results) is skipped silently.
_FOLDER_REPORT_KINDS = [
    ("inspection",   "01-inspection"),
    ("pv",           "02-pv-master"),
    ("boq",          "03-boq-capex"),
    ("cable",        "04-cable-sizing"),
    ("energy",       "05-energy-yield"),
    ("economic",     "06-economic"),
    ("installation", "07-installation"),
    ("workplan",     "08-workplan"),
    ("staffing",     "09-staffing"),
    ("proposal",     "10-proposal"),
]


@app.route("/folders")
@login_required
def folders_index():
    # List every distinct folder this user has used, with the project count.
    uid = session["user_id"]
    with get_db() as c:
        rows = c.execute(
            "SELECT COALESCE(NULLIF(folder,''),'(Unfiled)') AS f, COUNT(*) AS n "
            "FROM projects WHERE user_id=? GROUP BY f ORDER BY f",
            (uid,)).fetchall()
    folders = [{"name": r["f"], "count": r["n"]} for r in rows]
    return render_template("folders_index.html", user=current_user(), folders=folders)


@app.route("/folder/<path:name>")
@login_required
def folder_detail(name):
    # Render the contents of one folder. "(Unfiled)" is the synthetic bucket
    # for projects with an empty folder column.
    uid = session["user_id"]
    name = unquote(name).strip()
    is_unfiled = name in ("", "(Unfiled)")
    with get_db() as c:
        if is_unfiled:
            rows = c.execute(
                "SELECT * FROM projects WHERE user_id=? AND COALESCE(folder,'')='' "
                "ORDER BY updated_at DESC",
                (uid,)).fetchall()
        else:
            rows = c.execute(
                "SELECT * FROM projects WHERE user_id=? AND folder=? "
                "ORDER BY updated_at DESC",
                (uid, name)).fetchall()
    projects = []
    for p in rows:
        d = json.loads(p["data_json"] or "{}")
        has_results = bool(d.get("results"))
        projects.append({
            "id":          p["id"],
            "name":        p["name"],
            "updated":     (p["updated_at"] or "")[:16].replace("T", " "),
            "country":     d.get("country", ""),
            "location":    d.get("location", ""),
            "has_results": has_results,
            "report_kinds": _FOLDER_REPORT_KINDS if has_results else [],
        })
    display_name = "(Unfiled)" if is_unfiled else name
    return render_template("folder_detail.html",
                           user=current_user(),
                           folder_name=display_name,
                           folder_slug=("" if is_unfiled else name),
                           projects=projects,
                           report_kinds=_FOLDER_REPORT_KINDS)


@app.route("/folder/<path:name>/zip.zip")
@login_required
@limiter.limit("3 per minute")
def folder_zip(name):
    # Bundle every available PDF report for every project in the folder into
    # one ZIP. Uses the in-process Flask test_client to call existing PDF
    # routes — no duplication of PDF generation logic. Plan-gated reports
    # silently skip (4xx response from the inner call).
    uid = session["user_id"]
    name = unquote(name).strip()
    is_unfiled = name in ("", "(Unfiled)")
    with get_db() as c:
        if is_unfiled:
            rows = c.execute(
                "SELECT id, name FROM projects WHERE user_id=? AND COALESCE(folder,'')=''",
                (uid,)).fetchall()
        else:
            rows = c.execute(
                "SELECT id, name FROM projects WHERE user_id=? AND folder=?",
                (uid, name)).fetchall()
    if not rows:
        flash("That folder has no projects yet.", "warning")
        return redirect(url_for("folders_index"))

    buf = io.BytesIO()
    bundled = 0
    skipped = 0
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        with app.test_client() as client:
            # Forward our session so @login_required + tenant filters pass.
            with client.session_transaction() as sess:
                sess["user_id"] = session["user_id"]
                sess["username"] = session.get("username", "")
            for proj in rows:
                proj_folder = _safe_filename(f"{proj['id']:04d} - {proj['name']}")
                for kind, stub in _FOLDER_REPORT_KINDS:
                    url = url_for(f"export_pdf_{kind}", pid=proj["id"]) \
                        if f"export_pdf_{kind}" in app.view_functions \
                        else f"/project/{proj['id']}/report/{kind}/pdf"
                    try:
                        resp = client.get(url)
                    except Exception:
                        skipped += 1
                        continue
                    # Only accept real PDFs — many routes 302 to /results when the
                    # project has no calculation results yet.
                    ctype = (resp.headers.get("Content-Type") or "").lower()
                    if resp.status_code == 200 and "pdf" in ctype:
                        zf.writestr(f"{proj_folder}/{stub}.pdf", resp.data)
                        bundled += 1
                    else:
                        skipped += 1
        # Manifest so the user knows what was bundled vs skipped.
        manifest = (f"SolarPro Folder Export\n"
                    f"Folder: {('(Unfiled)' if is_unfiled else name)}\n"
                    f"User:   {session.get('username','')}\n"
                    f"At:     {datetime.utcnow().isoformat()}Z\n"
                    f"PDFs bundled: {bundled}\n"
                    f"PDFs skipped (plan-gated / no-results): {skipped}\n"
                    f"Projects: {len(rows)}\n")
        zf.writestr("MANIFEST.txt", manifest)

    if bundled == 0:
        flash("No completed reports yet in this folder. Run a project's calculations first.", "warning")
        return redirect(url_for("folder_detail", name=("(Unfiled)" if is_unfiled else name)))

    buf.seek(0)
    safe = _safe_filename(("Unfiled" if is_unfiled else name)).replace(" ", "_")
    return send_file(buf, mimetype="application/zip",
                     as_attachment=True,
                     download_name=f"SolarPro_{safe}_{datetime.utcnow():%Y%m%d}.zip")



# ─── Routes — PV Shading Factor Modelling ─────────────────────────────────────
#
# Implements `shading requirement1.txt` (Phase 1 — manual / inspection-driven
# factor selection; Phase 2 with the 3D AI agent is a follow-up).
#
# Flow: operator runs the wizard normally, then if the site inspection report
# confirms shading from any obstruction (tree, parapet, tower, mast, water
# tank, etc.), they click "Include Shading" on the loads page. That brings
# them to this page where they enter the obstruction geometry, pick a
# shading-loss class from the table, and save. The factor is stored under
# data["shading"]["factor"] on the project row; next loads-submit reads it
# and divides the base PV size by the factor (calc_pv shading_factor=).
#
# Table from the spec:
#   No shading              0%   1.00
#   Very light shading      5%   0.95
#   Light shading          10%   0.90
#   Moderate shading       15%   0.85
#   Significant shading    20%   0.80
#   Heavy shading          25%   0.75
#   Severe shading         30%   0.70
#   Very severe shading    40%   0.60


SHADING_FACTORS = [
    ("No shading",          "0%",  1.00),
    ("Very light shading",  "5%",  0.95),
    ("Light shading",       "10%", 0.90),
    ("Moderate shading",    "15%", 0.85),
    ("Significant shading", "20%", 0.80),
    ("Heavy shading",       "25%", 0.75),
    ("Severe shading",      "30%", 0.70),
    ("Very severe shading", "40%", 0.60),
]


def _shading_num(raw, default=0.0):
    # Parse a numeric field tolerantly. Empty/None/'' -> default; anything
    # unparseable -> default. Keeps the form forgiving so a partial save
    # doesn't 500.
    try:
        if raw is None or raw == "":
            return float(default)
        return float(str(raw).strip())
    except Exception:
        return float(default)


def _parse_obstructions(form):
    """Zip the parallel obs_*[] arrays from the shading form into a list of
    dicts. Empty trailing rows (no type AND no numeric value entered) are
    dropped so the operator can leave a card blank."""
    types     = form.getlist("obs_type[]")
    heights   = form.getlist("obs_height[]")
    widths    = form.getlist("obs_width[]")
    lengths_a = form.getlist("obs_length[]")
    diams_a   = form.getlist("obs_diameter[]")
    floors_a  = form.getlist("obs_floors[]")
    distances = form.getlist("obs_distance[]")
    dirs      = form.getlist("obs_direction[]")
    times     = form.getlist("obs_time[]")
    hours_a   = form.getlist("obs_hours[]")
    shaded_a  = form.getlist("obs_shaded_area_pct[]")
    seasons   = form.getlist("obs_season[]")
    mitig     = form.getlist("obs_mitigation[]")
    notes_a   = form.getlist("obs_notes[]")
    n = max(len(types), len(heights), len(widths), len(lengths_a),
            len(diams_a), len(floors_a), len(distances),
            len(dirs), len(times), len(hours_a), len(shaded_a),
            len(seasons), len(mitig), len(notes_a))
    out = []
    for i in range(n):
        def pick(arr, i):
            return arr[i] if i < len(arr) else ""
        row = {
            "type":            (pick(types, i) or "").strip()[:60],
            "height":          _shading_num(pick(heights, i)),
            "width":           _shading_num(pick(widths, i)),
            "length":          _shading_num(pick(lengths_a, i)),
            "diameter":        _shading_num(pick(diams_a, i)),
            "floors":          _shading_num(pick(floors_a, i)),
            "distance":        _shading_num(pick(distances, i)),
            "direction":       (pick(dirs, i) or "").strip()[:10],
            "time":            (pick(times, i) or "").strip()[:30],
            "hours":           _shading_num(pick(hours_a, i)),
            "shaded_area_pct": _shading_num(pick(shaded_a, i)),
            "season":          (pick(seasons, i) or "").strip()[:20],
            "mitigation":      (pick(mitig, i) or "").strip()[:60],
            "notes":           (pick(notes_a, i) or "").strip()[:400],
        }
        # Drop rows that are entirely empty (no type AND no numeric value).
        nums = (row["height"], row["width"], row["length"], row["diameter"], row["floors"], row["distance"], row["hours"], row["shaded_area_pct"])
        if not row["type"] and not any(nums) and not row["notes"]:
            continue
        out.append(row)
    return out


# Engine-first shading source of truth (2026-06-16) -- helpers below.
_AZIMUTH_LABEL_DEG = {
    "N": 0.0, "NORTH": 0.0,
    "NE": 45.0, "NORTH-EAST": 45.0, "NORTHEAST": 45.0,
    "E": 90.0, "EAST": 90.0,
    "SE": 135.0, "SOUTH-EAST": 135.0, "SOUTHEAST": 135.0,
    "S": 180.0, "SOUTH": 180.0,
    "SW": 225.0, "SOUTH-WEST": 225.0, "SOUTHWEST": 225.0,
    "W": 270.0, "WEST": 270.0,
    "NW": 315.0, "NORTH-WEST": 315.0, "NORTHWEST": 315.0,
}

def _coerce_float(value, default):
    # Tolerant float() that returns `default` on None/''/garbage.
    try:
        if value is None or value == "":
            return float(default)
        return float(value)
    except (TypeError, ValueError):
        return float(default)

def _azimuth_to_deg(value, default=180.0):
    # Accept compass labels ("South"/"South-East"/"S") OR numbers.
    if value is None:
        return float(default)
    if isinstance(value, (int, float)):
        return float(value)
    s = str(value).strip()
    if not s:
        return float(default)
    deg = _AZIMUTH_LABEL_DEG.get(s.upper())
    if deg is not None:
        return float(deg)
    try:
        return float(s)
    except ValueError:
        return float(default)

def _normalize_mount_type(raw):
    # Map any of the eight roof_type / mounting_type values down to
    # the three buckets the 3D scene actually branches on.
    # Inputs accepted: flat / pitched / hip / gable / metal / concrete /
    # ground / rooftop_pitched / rooftop_flat / rooftop_metal /
    # rooftop_membrane / ground_fixed / ground_tracking.
    s = (raw or "").strip().lower()
    if not s:
        return "rooftop_sloped"
    if "ground" in s:
        return "ground"
    if s in ("flat", "membrane", "concrete",
             "rooftop_flat", "rooftop_membrane"):
        return "rooftop_flat"
    # pitched / hip / gable / metal / rooftop_pitched / rooftop_metal
    return "rooftop_sloped"

def _apply_shading_factor(project, obstructions, base_shading=None):
    """Single source of truth for the shading factor.

    Runs _engine_full_analysis() first (real sun-position math). On
    engine success: writes the engine bucket into
    shading["factor"|"label"|"loss_pct"] and stores the full engine
    block at shading["engine"]. On engine failure (missing lat/lon
    etc.): falls back to the legacy heuristic so the page keeps
    working. Never raises.
    """
    out = dict(base_shading or {})
    out["obstructions"] = obstructions or []
    eng = None
    try:
        eng = _engine_full_analysis(project, out['obstructions'])
    except Exception:
        eng = None
    if eng:
        out["factor"]        = eng["bucket_factor"]
        out["label"]         = eng["bucket_label"]
        out["loss_pct"]      = eng["bucket_loss_pct"]
        out["engine"]        = eng
        out["factor_source"] = "engine"
        out["agent_version"] = "shading-engine-v1-2026-06-16"
        out["agent_summary"] = (
            f"Engine: {eng['bucket_label']} (factor {eng['bucket_factor']:.2f}, "
            f"{eng['bucket_loss_pct']:.1f}% loss) across {eng['affected_panels']} "
            f"of {eng['total_panels']} panels."
        )
        # Engine result has its own per-step series; clear the legacy
        # per-obstruction heuristic payload to avoid confusing the UI.
        out["per_obstruction"] = []
    elif obstructions:
        h = _compute_shading_factor(obstructions)
        out["factor"]            = h["factor"]
        out["label"]             = h["label"]
        out["loss_pct"]          = h["loss_pct"]
        out["combined_severity"] = h.get("combined_severity")
        out["per_obstruction"]   = h.get("per_obstruction", [])
        out["factor_source"]     = "heuristic_fallback"
        out["agent_version"]     = "phase1-deterministic-v1"
        out["agent_summary"]     = h.get("summary", "")
        out.pop("engine", None)
    else:
        out["factor"]            = 1.00
        out["label"]             = "No shading"
        out["loss_pct"]          = 0.0
        out["factor_source"]     = "no_obstructions"
        out["agent_version"]     = "shading-engine-v1-2026-06-16"
        out["agent_summary"]     = "No obstructions recorded -- shading factor 1.00 applied."
        out["per_obstruction"]   = []
        out.pop("engine", None)
    return out


def _ensure_engine_block(project, pid):
    """Populate data["shading"]["engine"] if it is missing.

    The /shading GET handler patches the engine in transiently so the
    dashboard always renders, but never saves it. As a result, routes
    that read directly from disk (the standalone shading report HTML +
    PDF) saw an empty engine block on any project that had never been
    saved through a POST. This helper runs the engine and persists.
    """
    try:
        data = project.get("data") or {}
        sh = data.get("shading", {}) or {}
        if sh.get("engine"):
            return
        eng = _engine_full_analysis(project, sh.get("obstructions") or [])
        if not eng:
            return
        sh = dict(sh)
        sh["engine"] = eng
        data["shading"] = sh
        save_project_data(pid, data)
        project["data"] = data
    except Exception as _e:
        try:
            app.logger.warning("engine-block backfill failed: %s", _e)
        except Exception:
            pass


def _compute_shading_factor(obstructions):
    """Phase 1 deterministic shading agent.

    Per-obstruction severity score (0..1) combines:
      geometric (height / distance) -- tall close obstruction matters most
      duration (hours/day shaded)
      affected PV area (%)
      time-of-day weight (midday > morning/afternoon > evening)
      seasonal weight (high > medium > low)
      mitigation multiplier (bypass diodes, optimisers, micro-inv reduce sev)

    Combined severity across N obstructions uses probabilistic union
    (1 - prod(1 - sev_i)) so a single shading source can never exceed 1.0
    and multiple sources combine sub-additively.

    Combined severity is then mapped to a loss% (0..40) and snapped to
    the nearest row in SHADING_FACTORS so the final factor is always one
    of the spec's 8 canonical classes.

    Returns a dict ready to persist on the project under data["shading"].
    Phase 2 swaps this for a true Google ADK agent with 3D simulation.
    """
    if not obstructions:
        return {
            "factor": 1.00, "label": "No shading", "loss_pct": 0.0,
            "combined_severity": 0.0, "per_obstruction": [],
            "summary": "No obstructions recorded -- shading factor 1.00 applied.",
        }
    TIME_W   = {"Morning": 0.65, "Midday": 1.00, "Afternoon": 0.65,
                "Evening": 0.35, "All day": 1.00}
    SEASON_W = {"Low": 0.50, "Medium": 0.75, "High": 1.00}
    MITIG_W  = {"None": 1.00, "Bypass diodes": 0.80, "DC optimisers": 0.60,
                "Micro-inverters": 0.50, "Combination": 0.40}
    per = []
    for o in obstructions:
        try: h = float(o.get("height") or 0)
        except Exception: h = 0.0
        try: d = max(float(o.get("distance") or 0), 0.5)
        except Exception: d = 0.5
        try: hours = float(o.get("hours") or 0)
        except Exception: hours = 0.0
        try: area_pct = float(o.get("shaded_area_pct") or 0)
        except Exception: area_pct = 0.0
        time_w   = TIME_W.get(o.get("time", "") or "Morning", 0.65)
        season_w = SEASON_W.get(o.get("season", "") or "Low", 0.50)
        mitig_w  = MITIG_W.get(o.get("mitigation", "") or "None", 1.00)
        geom = min(1.0, (h / d) / 3.0)
        dur  = min(1.0, hours / 6.0)
        area = min(1.0, area_pct / 100.0)
        sev  = 0.30*geom + 0.25*dur + 0.30*area + 0.10*time_w + 0.05*season_w
        sev  = max(0.0, min(1.0, sev * mitig_w))
        per.append({
            "type":      o.get("type", ""),
            "severity":  round(sev, 4),
            "geom":      round(geom, 3),
            "duration":  round(dur,  3),
            "area":      round(area, 3),
            "time_w":    time_w,
            "season_w":  season_w,
            "mitig_w":   mitig_w,
        })
    prod = 1.0
    for r in per:
        prod *= (1.0 - r["severity"])
    combined = 1.0 - prod
    loss_pct = combined * 40.0
    # Snap to nearest SHADING_FACTORS row (use highest row whose loss <= computed).
    best = SHADING_FACTORS[0]
    for row in SHADING_FACTORS:
        row_loss = float(row[1].rstrip("%"))
        if loss_pct >= row_loss:
            best = row
    return {
        "factor":             best[2],
        "label":              best[0],
        "loss_pct":           round(loss_pct, 1),
        "combined_severity": round(combined, 4),
        "per_obstruction":   per,
        "summary":            f"Combined severity {combined:.0%} across {len(obstructions)} obstruction(s) -> "
                              f"{best[0]} (factor {best[2]:.2f}, ~{best[1]} loss).",
    }




def _engine_full_analysis(project, obstructions, on_date=None,
                          step_minutes=30, mitigation_default="Bypass diodes"):
    """Run the deterministic shading engine for a project.

    Returns the engine.run_full_analysis() dict on success, or None if
    project context is incomplete or the engine raises. Never propagates
    exceptions to the route — falling back to the legacy heuristic keeps
    the page working if the engine path is broken.
    """
    try:
        # Import lazily so a missing engine module never crashes app startup.
        from engine.shading_engine import Obstruction, run_full_analysis
        from config.global_solar_data import GLOBAL_DATA
        from datetime import datetime as _dt

        data = project.get("data", {}) or {}
        country = (data.get("country") or "").strip()
        region  = (data.get("region")  or "").strip()
        # Prefer shading-form tilt/azimuth (set via inspection form or
        # /shading page), fall back to project-level Location values.
        # Azimuth may arrive as a compass label ("South") or a number.
        _sh_pre = data.get("shading") or {}
        tilt = _coerce_float(_sh_pre.get("tilt_deg"),
                             float(data.get("tilt_angle") or 15.0))
        azimuth = _azimuth_to_deg(
            _sh_pre.get("azimuth") if _sh_pre.get("azimuth") not in (None, "", 0)
            else data.get("azimuth"),
            180.0,
        )
        # Single mount-type value the 3D scene can branch on.
        mount_type = _normalize_mount_type(
            _sh_pre.get("roof_type") or data.get("mounting_type"))
        results = data.get("results", {}) or {}
        n_panels = int(results.get("num_panels") or 0)

        # Day-5 hotfix: default to 12 panels (typical residential
        # array) when Loads step hasn't produced num_panels yet so
        # the v2 dashboard renders a representative scene even on a
        # fresh project. Real PV sizing comes from the loads handler
        # downstream; this is just for the shading visualization.
        if n_panels <= 0:
            n_panels = 12

        # Lat/lon — try region table then fall back to country first-region.
        info = (GLOBAL_DATA.get(country) or {}).get("regions", {}).get(region)
        if not info:
            for v in (GLOBAL_DATA.get(country) or {}).get("regions", {}).values():
                info = v
                break
        if not info or "lat" not in info or "lon" not in info:
            return None

        lat = float(info["lat"])
        lon = float(info["lon"])

        # Pick the first non-None mitigation across obstructions; default
        # to Bypass diodes (covers the typical modern module).
        mitigation = mitigation_default
        for o in obstructions:
            m = (o.get("mitigation") or "").strip()
            if m and m.lower() != "none":
                mitigation = m
                break

        # Build engine Obstruction objects. The form gives us height +
        # width + distance + direction; depth is unknown, so we mirror the
        # width (square footprint) as a safe v1 default.
        engine_obs = []
        for i, o in enumerate(obstructions or []):
            try:
                engine_obs.append(Obstruction(
                    obs_id=i + 1,
                    type=str(o.get("type") or "obstruction"),
                    height_m=float(o.get("height") or 0),
                    width_m=float(o.get("width") or 0),
                    depth_m=float(o.get("width") or 0),
                    distance_m=float(o.get("distance") or 0),
                    direction=str(o.get("direction") or "South"),
                    mitigation=str(o.get("mitigation") or "None"),
                    notes=str(o.get("notes") or ""),
                ))
            except Exception:
                continue

        if on_date is None:
            # 3d10 plan: sim_date/sim_time picker (2026-06-16 late).
            # Read the form-persisted simulation date if set, else fall
            # back to summer solstice (21 June) for worst-case analysis.
            _sd_raw = (_sh_pre.get("sim_date") or "").strip()
            on_date = None
            if _sd_raw:
                try:
                    on_date = _dt.strptime(_sd_raw[:10], "%Y-%m-%d")
                except Exception:
                    on_date = None
            if on_date is None:
                on_date = _dt(_dt.utcnow().year, 6, 21)

        result = run_full_analysis(
            lat_deg=lat, lon_deg=lon, on_date=on_date,
            tz_offset_h=0.0,
            num_panels=n_panels, tilt_deg=tilt,
            array_azimuth_deg=azimuth,
            mount_height_m=float(data.get("shading", {}).get("roof_height_m") or 1.0),
            obstructions=engine_obs,
            mitigation=mitigation,
            step_minutes=step_minutes,
        )

        # Strip non-JSON-serialisable bits (Panel/TimeStepResult are dataclasses
        # containing tuples — fine for json.dumps in Python 3, but we still
        # shape it for the UI so the template stays simple).
        return {
            "lat":                lat,
            "lon":                lon,
            "on_date":            on_date.strftime("%Y-%m-%d"),
            "tilt_deg":           tilt,
            "array_azimuth_deg":  azimuth,
            "mount_type":         mount_type,
            "total_panels":       result["total_panels"],
            "affected_panels":    result["affected_panels"],
            "heavily_affected":   result["heavily_affected"],
            "shading_start":      result["shading_start"],
            "shading_end":        result["shading_end"],
            "shading_duration_h": result["shading_duration_h"],
            "system_loss_pct":    result["energy"]["system_loss_pct"],
            "peak_step_loss_pct": result["energy"]["peak_step_loss_pct"],
            "weighted_avg_fraction": result["energy"]["weighted_avg_fraction"],
            "bucket_label":       result["bucket_label"],
            "bucket_loss_pct":    result["bucket_loss_pct"],
            "bucket_factor":      result["bucket_factor"],
            "mitigation":         result["mitigation"],
            "n_strings":          result["n_strings"],
            # Snapshot of per-step shading for the time slider.
            # Each entry: {time, alt, az, avg_frac, partially, fully}.
            "series": [
                {
                    "time": s.when.strftime("%H:%M"),
                    "alt":  round(s.altitude_deg, 1),
                    "az":   round(s.azimuth_deg, 1),
                    "avg_frac": round(s.avg_fraction, 4),
                    "partially": s.panels_partially_shaded,
                    "fully":     s.panels_fully_shaded,
                    # Day-3 add: per-panel fraction at THIS step
                    # so the time slider can re-color panels live.
                    "panel_fracs": [round(f, 3) for f in s.per_panel_fraction],
                }
                for s in result["series"]
            ],
            # Per-panel max shaded fraction across the day (for grid heatmap).
            "per_panel_max_frac": [
                round(max((s.per_panel_fraction[i] for s in result["series"]), default=0.0), 3)
                for i in range(result["total_panels"])
            ],
            # Per-panel 5-class severity bucket (matches the heat-map
            # colour code in templates/shading.html and the spec image).
            # unshaded / light / moderate / heavy / full.
            "per_panel_bucket": [
                ("full"     if f >= 0.95 else
                 "heavy"    if f >= 0.50 else
                 "moderate" if f >= 0.20 else
                 "light"    if f >= 0.05 else
                 "unshaded")
                for f in (
                    round(max((s.per_panel_fraction[i] for s in result["series"]), default=0.0), 3)
                    for i in range(result["total_panels"])
                )
            ],
            # Engine version stamp — bump when the algorithm changes so we
            # can detect stale persisted results.
            "engine_version": "shading-engine-v1-2026-06-14",
        }
    except Exception as _e:
        try:
            app.logger.warning("shading engine failure (falling back): %s", _e)
        except Exception:
            pass
        return None


@app.route("/project/<int:pid>/shading", methods=["GET", "POST"])
@login_required
@limiter.limit("30 per hour")
def project_shading(pid):
    project = get_project(pid)
    if not project:
        flash("Project not found.", "warning")
        return redirect(url_for("dashboard"))

    if request.method == "POST":
        csrf_protect()
        # Save-manual-factor: human-driven override of the agent pick.
        # Bypasses the obstruction parser + agent run; just persists
        # the chosen factor + a "source=manual" tag.
        _smf_raw = request.form.get("save_manual_factor") or ""
        if _smf_raw:
            try:
                _smf = float(_smf_raw)
            except Exception:
                _smf = 0.0
            if 0.55 <= _smf <= 1.05:
                data = project["data"]
                _existing = data.get("shading", {}) or {}
                from engine.shading_engine import pick_shading_bucket as _psb
                _label, _loss, _f = _psb((1.0 - _smf) * 100)
                _existing["factor"] = _smf
                _existing["label"] = _label
                _existing["loss_pct"] = _loss
                _existing["factor_source"] = "manual"
                _existing["saved_at"] = datetime.utcnow().isoformat() + "Z"
                _existing["saved_by"] = session.get("username", "")
                data["shading"] = _existing
                save_project_data(pid, data)
                _write_audit_event("shading_factor_manual_set",
                    user_id=session.get("user_id"), username=session.get("username", ""),
                    ip=_get_real_ip(),
                    details=f"pid={pid} factor={_smf:.2f} label={_label}")
                flash(f"Manual shading factor saved: {_smf:.2f} ({_label}, {_loss:.0f}% loss). "
                      f"Re-run the loads step to apply.", "success")
                return redirect(url_for("project_shading", pid=pid))
            else:
                flash("Manual factor must be between 0.55 and 1.05.", "warning")
                return redirect(url_for("project_shading", pid=pid))
        # Parse the obstruction cards first, then let the agent decide the
        # shading factor from those inputs. Per owner spec, the operator
        # models the obstructions; the agent picks the factor.
        obstructions = _parse_obstructions(request.form)
        data = project["data"]
        # Engine-first source of truth (fix 2026-06-16): build the
        # shading scalars from the form, then run the deterministic
        # engine via _apply_shading_factor. The engine drives factor /
        # label / loss_pct so the dashboard banner, the 3D scene, the
        # agent narrative, and the PV-sizing card all agree.
        _existing = data.get("shading", {}) or {}
        _existing.update({
            "units":                ("imperial" if (request.form.get("units","") == "imperial") else "metric"),
            "tilt_deg":             _shading_num(request.form.get("tilt_deg")),
            "azimuth":              (request.form.get("azimuth", "") or "").strip()[:30],
            "roof_type":            (request.form.get("roof_type", "") or "").strip()[:40],
            "mount_type":           _normalize_mount_type(
                                       request.form.get("roof_type") or data.get("mounting_type")),
            "roof_height_m":        _shading_num(request.form.get("roof_height_m")),
            # Owner directive 2026-06-21: real operator-entered building
            # dimensions drive the 3D scene + engine, not a fake h*2.8.
            "building_width_m":     _shading_num(request.form.get("building_width_m")),
            "building_length_m":    _shading_num(request.form.get("building_length_m")),
            "inspection_confirmed": bool(request.form.get("inspection_confirmed")),
            # 3d10 plan sim_date/sim_time picker (2026-06-16 late).
            # YYYY-MM-DD + HH:MM strings; the engine reads sim_date in
            # _engine_full_analysis, the dashboard JS seeds the time
            # slider with sim_time on initial render.
            "sim_date":             (request.form.get("sim_date", "") or "").strip()[:10],
            "sim_time":             (request.form.get("sim_time", "") or "").strip()[:5],
            "obstructions":         obstructions,
            "saved_at":             datetime.utcnow().isoformat() + "Z",
            "saved_by":             session.get("username", ""),
        })
        # Clear stale engine output so the helper re-runs on this save.
        _existing.pop("engine", None)
        data["shading"] = _existing
        project["data"] = data
        data["shading"] = _apply_shading_factor(
            project, obstructions, base_shading=data["shading"])
        factor = data["shading"]["factor"]
        save_project_data(pid, data)
        # myproject result-history feature (2026-06-16):
        # Append the agent narrative to shading_history then strip it
        # from the project record so the dashboard stops dumping the
        # walkthrough. The factor + bucket label stay on the project
        # so loads/calc continues to work.
        try:
            _sh = data.get("shading", {}) or {}
            _narr = _sh.get("agent_summary", "") or ""
            with get_db() as _c:
                _c.execute(
                    "INSERT INTO shading_history "
                    "(user_id, username, project_id, project_name, location, "
                    " mount_type, factor, label, loss_pct, agent_narrative, "
                    " agent_version, obstructions_n) "
                    "VALUES (?,?,?,?,?,?,?,?,?,?,?,?)",
                    (session.get("user_id") or 0,
                     session.get("username", "") or "",
                     pid,
                     project.get("name", "") or "",
                     (str(data.get("region","") or "") + ", " +
                      str(data.get("country","") or "")).strip(", "),
                     _sh.get("mount_type", "") or "",
                     float(_sh.get("factor") or 1.0),
                     _sh.get("label", "") or "",
                     float(_sh.get("loss_pct") or 0),
                     _narr[:4000],
                     _sh.get("agent_version", "") or "",
                     len(obstructions or [])))
        except Exception as _hist_err:
            try:
                app.logger.warning(
                    "shading_history insert failed: %s", _hist_err)
            except Exception:
                pass
        # Strip agent walkthrough from project record (owner spec:
        # "the agent must delete its result on success ... no holding
        # on to results"). Keep factor/label/loss_pct so loads works.
        try:
            _sh2 = data.get("shading") or {}
            for _k in ("agent_v2", "agent_summary", "per_obstruction",
                       "combined_severity"):
                _sh2.pop(_k, None)
            data["shading"] = _sh2
            save_project_data(pid, data)
        except Exception:
            pass

        # Audit log — operator overrode the un-shaded design. Important record
        # because the corrected PV size is materially larger.
        _write_audit_event("shading_factor_set",
            user_id=session.get("user_id"), username=session.get("username", ""),
            ip=_get_real_ip(),
            details=f"pid={pid} factor={factor:.2f} label={data['shading'].get('label','')}")

        if factor >= 0.999:
            flash("Shading agent: no obstructions found (factor 1.00). The base PV size will be used.", "info")
        else:
            flash(f"Shading agent picked factor {factor:.2f} ({data['shading'].get('label','')}, "
                  f"{data['shading'].get('loss_pct',0):.1f}% loss) from {len(obstructions)} obstruction(s). "
                  f"Re-run the loads step to apply.",
                  "success")
        # Route by which action button was used (spec image's 6-button
        # footer). "run_ai" stays on the shading page so the operator
        # sees the new factor + 3D scene. "calculate" / "recalculate"
        # go to /loads so PV sizing re-runs with the new factor. Any
        # other value (or none) keeps the legacy /loads redirect.
        _action = (request.form.get("action") or "").strip().lower()
        if _action == "run_ai":
            return redirect(url_for("project_shading", pid=pid))
        return redirect(url_for("project_loads", pid=pid))

    shading = project["data"].get("shading", {}) or {}
    # Day-5 hotfix: if the v2 flag is set and the engine has
    # never run on this project, run it now using whatever
    # obstructions are already saved. Result is local-only
    # (we do NOT save_project_data on GET); it persists only
    # when the operator hits Save on the form.
    # ?demo=<level> injects sample obstructions so the dashboard shows
    # something even on a project with no real obstructions saved. The
    # operator can test the engine + agent + 3D scene with one click.
    _demo = (request.args.get("demo") or "").strip().lower()
    # Calibrated 2026-06-14 against engine output at Accra/12 panels:
    #   demo=10  -> 5m tree  6m East  -> 12.3% loss -> 0.90 Light
    #   demo=20  -> 5m tree  5m East  -> 23.8% loss -> 0.80 Significant
    #   demo=25  -> 6m wall  6m East  -> 25.0% loss -> 0.75 Heavy
    #   demo=30  -> 5m wall  5m East  -> 36.3% loss -> 0.70 Severe
    _demo_obs = {
        "10":  [{"type": "tree", "height": 5.0, "width": 3.0,
                 "distance": 6.0, "direction": "East",
                 "mitigation": "Bypass diodes",
                 "notes": "demo: light shading (single tree to the east)"}],
        "20":  [{"type": "tree", "height": 4.0, "width": 4.0,
                 "distance": 5.0, "direction": "East",
                 "mitigation": "Bypass diodes",
                 "notes": "demo: significant shading (closer tree)"}],
        "25":  [{"type": "boundary wall", "height": 6.0, "width": 5.0,
                 "distance": 6.0, "direction": "East",
                 "mitigation": "Bypass diodes",
                 "notes": "demo: heavy shading (wall to the east)"}],
        "30":  [{"type": "boundary wall", "height": 5.0, "width": 5.0,
                 "distance": 5.0, "direction": "East",
                 "mitigation": "Bypass diodes",
                 "notes": "demo: severe shading (wall close in)"}],
    }
    if _demo in _demo_obs:
        shading = dict(shading)
        shading["obstructions"] = _demo_obs[_demo]
        shading.pop("engine", None)
        shading.pop("agent_v2", None)

    # Engine runs on GET whenever no engine output exists yet, regardless
    # of the v1/v2 flag — the template decides which view to render.
    if not shading.get("engine"):
        try:
            _eng = _engine_full_analysis(project, shading.get("obstructions") or [])
            if _eng:
                shading = dict(shading)
                shading["engine"] = _eng
                # Skip the LLM agent on GET (free-tier latency 5-30s).
                # Agent runs only when the operator saves the form.
        except Exception as _e:
            try:
                app.logger.warning("v2 GET engine failure: %s", _e)
            except Exception:
                pass
    # Manual factor override (operator picks a factor; PV calc +
    # agent narrative reflect that scenario).
    try:
        _mf = float(request.args.get("manual_factor") or 0)
    except Exception:
        _mf = 0.0
    if 0.55 <= _mf <= 1.05 and shading.get("engine"):
        shading = dict(shading)
        _eng2 = dict(shading["engine"])
        _eng2["bucket_factor"] = _mf
        from engine.shading_engine import pick_shading_bucket as _psb
        _label, _loss, _f = _psb((1.0 - _mf) * 100)
        _eng2["bucket_label"] = _label
        _eng2["bucket_loss_pct"] = _loss
        shading["engine"] = _eng2
        shading["manual_override"] = {"factor": _mf, "label": _label,
                                       "loss_pct": _loss}
    # AI 3D Shading Agent v2: pick reference template (2026-06-16)
    # See engine/shading_templates.py + ADR for the catalogue + scoring.
    reference_template = None
    try:
        from engine.shading_templates import pick_reference_template as _prt
        _eng_block = shading.get("engine") or {}
        reference_template = _prt({
            "mount_type":    shading.get("mount_type") or _eng_block.get("mount_type"),
            "obstructions":  shading.get("obstructions") or [],
            "bucket_factor": _eng_block.get("bucket_factor") or shading.get("factor") or 0,
        })
    except Exception as _e:
        try:
            app.logger.warning("reference template pick failed: %s", _e)
        except Exception:
            pass
    # Manual scene-type override (3d10.txt section 5). If ?scene= is set,
    # swap reference_template for the catalogue entry of the requested
    # scene type so the user can audit how a different scene would render.
    _forced_scene = (request.args.get("scene") or "").strip()
    if _forced_scene and reference_template:
        try:
            from engine.shading_templates import load_catalogue as _lc
            _cat = _lc()
            _match = next((t for t in (_cat.get("templates") or [])
                           if t.get("scene_type") == _forced_scene), None)
            if _match:
                reference_template = dict(reference_template)
                reference_template["template_id"] = _match["id"]
                reference_template["scene_type"]  = _match.get("scene_type", "")
                reference_template["title"]       = _match.get("title", "")
                reference_template["template"]    = _match
                reference_template["match_score"] = 1.0
                reference_template["forced"]      = True
                reference_template["reasoning"]   = (
                    "Manual override: scene type forced to \""
                    + _forced_scene.replace("_", " ")
                    + "\" by user (auto-match disabled).")
        except Exception as _eo:
            try:
                app.logger.warning("scene override failed: %s", _eo)
            except Exception:
                pass
    return render_template("shading.html",
                           user=current_user(),
                           project=project,
                           shading=shading,
                           reference_template=reference_template,
                           shading_factors=SHADING_FACTORS)



# Shading Report routes — added 2026-06-14. Three routes:
#   GET  /project/<pid>/report/shading      → HTML (printable)
#   GET  /project/<pid>/report/shading/pdf  → PDF via markdown-pdf
# Email is handled through the existing /project/<pid>/email pipeline
# (REPORT_OPTIONS gets a new entry below).


@app.route("/project/<int:pid>/report/shading")
@login_required
def report_shading(pid):
    """HTML view of the AI 3D Shading Simulation report — printable +
    standalone link the operator can hand to a client or attach to a
    drawing pack."""
    project = get_project(pid)
    if not project:
        flash("Project not found.", "warning")
        return redirect(url_for("dashboard"))
    # Ensure engine angles are present even on projects that were last
    # touched before the engine-first fix. Persists, so subsequent loads
    # are a no-op.
    _ensure_engine_block(project, pid)
    return render_template("report_shading.html",
                           user=current_user(),
                           project=project,
                           d=project["data"],
                           shading=project["data"].get("shading", {}) or {},
                           r=project["data"].get("results", {}) or {})


@app.route("/project/<int:pid>/report/shading/pdf")
@login_required
@limiter.limit("5 per minute")
def export_pdf_shading(pid):
    """PDF export — Shading Analysis Report."""
    gate = _paid_only(pid)
    if gate: return gate
    project = get_project(pid)
    if not project:
        flash("Project not found.", "warning")
        return redirect(url_for("dashboard"))
    # Backfill engine block if missing so the PDF carries angles.
    _ensure_engine_block(project, pid)
    d   = project["data"]
    r   = d.get("results", {}) or {}
    sh  = d.get("shading", {}) or {}
    eng = sh.get("engine", {}) or {}
    ag  = sh.get("agent_v2", {}) or {}
    sym = d.get("symbol", "$")

    factor       = float(sh.get("factor") or eng.get("bucket_factor") or 1.0)
    label        = sh.get("label") or eng.get("bucket_label") or "No shading"
    loss_pct     = float(sh.get("loss_pct") or eng.get("bucket_loss_pct") or 0.0)
    source       = sh.get("factor_source") or ("agent" if ag else "engine")
    pv_base      = float(r.get("pv_kw_base") or r.get("pv_kw") or 0)
    pv_corrected = (pv_base / factor) if factor and factor > 0 else pv_base
    pv_recommended = math.ceil(pv_corrected) if pv_corrected else 0

    obstructions = sh.get("obstructions", []) or []

    # ── Header ──────────────────────────────────────────────────────────
    md = f"""# Shading Analysis Report — {project["name"]}

**{d.get("region","")}, {d.get("country","")}** · {d.get("system_type","off-grid").title()} System

Prepared by: SolarPro Global · BS 7671:2018 · IEC 61853 · IEC 62446

---

## 1. Executive Summary

This report documents the AI 3D Shading Simulation performed on the
**{project["name"]}** site. The shading factor was determined from
on-site obstruction geometry (height, distance, direction), the site's
solar geometry (latitude {eng.get("lat","--")}°, longitude
{eng.get("lon","--")}°), and the electrical-string behaviour of the PV
modules under partial shade.

| Metric | Value |
|---|---|
| **AI selected shading factor** | **{factor:.2f}** |
| **Severity bucket** | {label} |
| **Estimated energy loss** | {loss_pct:.1f}% |
| **Affected panels (peak step)** | {eng.get("affected_panels","--")} of {eng.get("total_panels","--")} |
| **Daily shading window** | {eng.get("shading_start","--")} – {eng.get("shading_end","--")} ({eng.get("shading_duration_h","--")} hours) |
| **Mitigation in place** | {eng.get("mitigation", sh.get("mitigation", "Bypass diodes"))} |
| **Factor source** | {source} |

---

## 2. Site Geometry

| Parameter | Value |
|---|---|
| Latitude | {eng.get("lat","--")}° N |
| Longitude | {eng.get("lon","--")}° E |
| Analysis date | {eng.get("on_date","21 June (summer solstice)")} |
| Array tilt | {eng.get("tilt_deg","--")}° |
| Array azimuth | {eng.get("array_azimuth_deg","--")}° |
| Total panels | {eng.get("total_panels","--")} |
| Strings | {eng.get("n_strings","--")} |

---

## 3. Obstruction Register

"""
    if obstructions:
        md += "| # | Type | Height (m) | Width (m) | Distance (m) | Direction | Mitigation |\n"
        md += "|---|---|---|---|---|---|---|\n"
        for i, o in enumerate(obstructions, 1):
            md += (f"| {i} | {o.get('type','—')} | {float(o.get('height',0)):.1f} | "
                   f"{float(o.get('width',0)):.1f} | {float(o.get('distance',0)):.1f} | "
                   f"{o.get('direction','—')} | {o.get('mitigation','None')} |\n")
    else:
        md += "_No obstructions recorded on this project._\n"

    md += """

---

## 4. AI Shading Agent — Narrative Analysis

"""
    if ag and ag.get("narrative"):
        md += f"{ag.get('narrative')}\n\n"
    else:
        md += (f"The deterministic shading engine computed a factor of "
               f"**{factor:.2f}** ({label}, {loss_pct:.1f}% loss) for this "
               f"site. See the per-obstruction table above and the system "
               f"recommendation in section 6.\n\n")

    if ag and ag.get("per_obstruction"):
        md += "### Per-obstruction impact\n\n"
        md += "| Obstruction | Impact | Mitigation recommendation |\n"
        md += "|---|---|---|\n"
        for r2 in ag["per_obstruction"]:
            md += (f"| {r2.get('ref','—')} | {r2.get('impact','—')} | "
                   f"{r2.get('mitigation','—')} |\n")
        md += "\n"

    if ag and ag.get("factor_reasoning"):
        md += f"**Factor reasoning:** {ag['factor_reasoning']}\n\n"

    if ag and ag.get("what_ifs"):
        md += "### Mitigation what-ifs\n\nIf you change the mitigation strategy, the agent estimates:\n\n"
        md += "| Scenario | Expected factor | Expected loss | Reasoning |\n"
        md += "|---|---|---|---|\n"
        for w in ag["what_ifs"]:
            md += (f"| {w.get('scenario','—')} | "
                   f"{w.get('expected_factor','—')} | "
                   f"{w.get('expected_loss_pct','—')}% | "
                   f"{w.get('reasoning','—')} |\n")
        md += "\n"

    md += f"""---

## 5. PV System Sizing — With Shading Correction

The corrected PV array size is the base size divided by the shading
factor. This ensures that even with the modelled shading loss, the
system still delivers the design daily energy demand.

| Step | Value |
|---|---|
| Base PV size (no shading) | **{pv_base:.2f} kWp** |
| AI selected shading factor | **{factor:.2f}** ({label}) |
| Corrected PV size | **{pv_corrected:.2f} kWp** |
| Recommended PV size (rounded up) | **{pv_recommended} kWp** |

Formula: `Corrected PV Size = Base PV Size ÷ Shading Factor`

For this project: `{pv_base:.2f} / {factor:.2f} = {pv_corrected:.2f} kWp` rounded to **{pv_recommended} kWp**.

---

## 5b. Concluding Action - Sizing Decision

"""
    _orig_panels = int(r.get("num_panels", 0) or 0)
    _panel_wp = int(r.get("panel_wp", 400) or 400)
    _extra_kwp = pv_corrected - pv_base
    _extra_panels = int(math.ceil(_extra_kwp * 1000 / _panel_wp)) if _panel_wp > 0 else 0
    _new_panels = _orig_panels + _extra_panels
    _daily_kwh = float(r.get("daily_kwh", 0) or 0)
    if factor >= 0.999:
        md += (f"No shading was detected on this site. The original PV array of "
               f"**{_orig_panels} panels ({pv_base:.2f} kWp)** will deliver the "
               f"design daily energy demand of **{_daily_kwh:.2f} kWh/day** without "
               f"adjustment. **No re-sizing required.**\n\n")
    else:
        _useful = pv_base * factor
        md += (f"Due to **{loss_pct:.1f}% shading loss** ({label}) at this site, "
               f"the original PV array of **{_orig_panels} panels "
               f"({pv_base:.2f} kWp)** would only deliver about "
               f"**{_useful:.2f} kWp** of usable capacity against the design "
               f"daily energy demand of **{_daily_kwh:.2f} kWh/day**.\n\n"
               f"**Therefore**, the array must be increased to "
               f"**{_new_panels} panels ({pv_recommended} kWp installed)** "
               f"so the shaded array still produces the required energy. "
               f"That is **{_extra_panels} additional panels** "
               f"({_extra_kwp:.2f} kWp extra) beyond the un-shaded design.\n\n")
        if factor < 0.85:
            _mit = "DC optimisers" if factor >= 0.75 else "micro-inverters (Enphase IQ8)"
            md += (f"**Alternative path:** install {_mit} to recover most of the "
                   f"loss without adding panels - capex vs roof-area trade-off.\n\n")
    md += """---

## 6. Recommendations

"""
    if factor >= 0.999:
        md += ("- No additional PV capacity is required for shading.\n"
               "- Re-confirm during commissioning that the site stays free "
               "of new obstructions (trees, mast retrofits, neighbour builds).\n")
    elif factor >= 0.90:
        md += ("- Light shading detected. Standard module-level bypass diodes "
               "are sufficient — no per-panel electronics required.\n"
               "- Re-confirm panel layout avoids the morning/evening shadow "
               "windows where possible.\n"
               f"- Use the recommended {pv_recommended} kWp array size.\n")
    elif factor >= 0.80:
        md += ("- Moderate to significant shading. Consider DC optimisers "
               "(Tigo, SolarEdge HD-Wave) on the affected string(s) to "
               "eliminate string-mismatch losses.\n"
               "- If practical, increase row spacing or relocate the array "
               "away from the dominant obstruction.\n"
               f"- Use the recommended {pv_recommended} kWp array size.\n")
    else:
        md += ("- Heavy or severe shading. Strongly recommend DC optimisers "
               "OR micro-inverters (Enphase IQ8) on the entire array to "
               "decouple per-panel MPPT.\n"
               "- If the dominant obstruction is removable (tree pruning, "
               "antenna relocation), the financial case for removal is "
               "typically 18-36 months payback.\n"
               f"- Use the recommended {pv_recommended} kWp array size.\n"
               "- Add a performance-monitoring system (e.g. Solar-Log, Tigo "
               "TS4) so the array's daily yield is tracked against the "
               "shading model post-installation.\n")

    md += f"""

---

## 7. Methodology

The AI 3D Shading Simulation Agent uses:

1. **Sun position** via the NOAA Solar Position Algorithm (≈0.1°
   accuracy) at the site GPS coordinates.
2. **3D ray-cast shadow projection** from each obstruction's bounding
   geometry onto the panel array plane.
3. **Per-panel intersection** via convex polygon clipping
   (Sutherland-Hodgman) at 30-minute intervals across the day.
4. **Electrical-string model** that applies the correct loss formula
   per mitigation strategy: None / Bypass diodes (3 substrings per
   panel + Kirchhoff string penalty) / DC optimisers / Micro-inverters
   (per-panel MPPT).
5. **8-bucket conservative pick** matching the project's
   `SHADING_FACTORS` table; if computed loss falls between bands, the
   conservative (higher-loss) bucket is selected.
6. **Narrative explanation** from a Google-ADK `LlmAgent` whose system
   prompt carries NREL solar geometry, IEC 61853 string-electrical
   behaviour, and common site patterns.

---

*Shading Analysis Report — {project["name"]}*
*Generated by SolarPro Global · AI 3D Shading Simulation Agent v1*
"""
    fname = f"Shading_Report_{project['name'].replace(' ','_')}.pdf"
    return _render_pdf(f"Shading Analysis Report — {project['name']}", md, fname)


