def _ensure_marketplace_tables():
    if bool(os.environ.get("DATABASE_URL")):
        _ensure_marketplace_schema_postgres()
        # 2026-06-22 (session B): extra columns on product_categories so the
        # admin Manage Categories page can SELECT them on Postgres too.
        for _ddl in (
            "ALTER TABLE product_categories ADD COLUMN IF NOT EXISTS default_unit VARCHAR(20) DEFAULT 'No.'",
            "ALTER TABLE product_categories ADD COLUMN IF NOT EXISTS subcategories_csv TEXT DEFAULT ''",
            "ALTER TABLE product_categories ADD COLUMN IF NOT EXISTS spec_fields_csv TEXT DEFAULT ''",
            "ALTER TABLE boq_projects ADD COLUMN IF NOT EXISTS services_csv TEXT DEFAULT ''",
            "ALTER TABLE marketplace_bom_items ADD COLUMN IF NOT EXISTS description TEXT DEFAULT ''",
            "ALTER TABLE marketplace_bom_items ADD COLUMN IF NOT EXISTS specification TEXT DEFAULT ''",
            "ALTER TABLE marketplace_bom_items ADD COLUMN IF NOT EXISTS brand TEXT DEFAULT ''",
        ):
            try:
                with get_db() as _c:
                    _c.execute(_ddl)
            except Exception:
                pass
        # 2026-06-22: also seed canonical Ghana suppliers + products on Postgres.
        try: _seed_ghana_suppliers_products()
        except Exception: pass
        # 2026-06-22 (session B): seed product_brands on Postgres too.
        try: _seed_marketplace_brands()
        except Exception: pass
        # 2026-06-22 (session C): library expansion on Postgres too.
        try: _seed_library_expansion()
        except Exception: pass
        return
    """Idempotent — runs on every marketplace route hit. Cheap (CREATE IF NOT EXISTS)."""
    with get_db() as c:
        c.executescript(
            """
            CREATE TABLE IF NOT EXISTS product_categories (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                code          TEXT UNIQUE NOT NULL,
                name          TEXT NOT NULL,
                icon          TEXT DEFAULT 'bi-box',
                display_order INTEGER DEFAULT 0,
                is_active     INTEGER DEFAULT 1,
                created_at    TEXT DEFAULT CURRENT_TIMESTAMP
            );
            CREATE INDEX IF NOT EXISTS idx_product_categories_order
                ON product_categories(display_order);
            """
        )
        # Extend equipment_catalog with marketplace fields (idempotent — PRAGMA check first).
        cols = {r["name"] for r in c.execute("PRAGMA table_info(equipment_catalog)").fetchall()}
        if "category_id" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN category_id INTEGER DEFAULT 0")
        if "subcategory" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN subcategory TEXT DEFAULT ''")
        if "image_url" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN image_url TEXT DEFAULT ''")
        if "is_public_visible" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN is_public_visible INTEGER DEFAULT 1")
        # 2026-06-27 (Item B) -- voltage/frequency/standards for country-grid compliance
        if "voltage_v" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN voltage_v REAL DEFAULT 0")
        if "frequency_hz" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN frequency_hz REAL DEFAULT 0")
        if "compliance_standards" not in cols:
            c.execute("ALTER TABLE equipment_catalog ADD COLUMN compliance_standards TEXT DEFAULT ''")
        # Upsert categories -- INSERT OR IGNORE so adding a new entry to
        # _MARKETPLACE_CATEGORIES lands in pre-existing databases too.
        # Original seed-once-when-empty pattern silently skipped new entries.
        for _row in _MARKETPLACE_CATEGORIES:
            c.execute(
                "INSERT OR IGNORE INTO product_categories "
                "(code,name,icon,display_order) VALUES (?,?,?,?)",
                _row,
            )
        # Backfill: any equipment_catalog row with category_id=0 maps to Solar Equipment.
        solar_cat = c.execute(
            "SELECT id FROM product_categories WHERE code='solar_equipment'"
        ).fetchone()
        if solar_cat:
            c.execute(
                "UPDATE equipment_catalog SET category_id=? WHERE category_id=0 AND category_id IS NOT NULL",
                (solar_cat["id"],),
            )
        # Seed a handful of electrical products so the marketplace isn't empty on first visit.
        if c.execute(
            "SELECT COUNT(*) FROM equipment_catalog WHERE category_id IN "
            "(SELECT id FROM product_categories WHERE code != 'solar_equipment')"
        ).fetchone()[0] == 0:
            _seed_marketplace_samples(c)
        else:
            # Per-category top-up: when _MARKETPLACE_CATEGORIES gains a new
            # entry that ships with starter samples (e.g. power_system),
            # populate ONLY those empty categories without re-seeding others.
            _backfill_marketplace_samples_for_empty_categories(c)
    try: _ensure_product_link_columns()
    except Exception: pass
    # 2026-06-22: seed canonical Ghana-local suppliers + their price-sheet products.
    try: _seed_ghana_suppliers_products()
    except Exception: pass
    # 2026-06-22 (session B): seed product_brands.
    try: _seed_marketplace_brands()
    except Exception: pass
    # 2026-06-22 (session C): library expansion seed.
    try: _seed_library_expansion()
    except Exception: pass


