    nexans    = sup.get("Nexans", rs)
    generic   = sup.get("Generic", rs)
    mk        = sup.get("MK", rs)
    abb       = sup.get("ABB", schneider)

    # (category_code, name, brand, model, spec, unit, price_usd, supplier_id, lead_time, subcategory)
