# ─── Routes — BOM Rates Panel + Excel + PDF export ────────────────────────────
# Slice 8: convert a marketplace BOM (basic supplier prices) into a full BOQ
# by adding labour + overhead + profit + VAT markups, then export as Excel
# (.xlsx via openpyxl) or PDF (via solar's existing MarkdownPdf chain).

_BOM_DEFAULT_RATES = {
    # Task #4 (2026-06-24): BOM aligned to BOQ chain --
    #   final = direct * (1 + (ovh+prf)/100) * (1 + cnt/100) * (1 + vat/100)
    #   where direct = basic * (1 + lab/100).
    # Sum OH+P (was compound) + new contingency layer.
    "labour_pct":     15.0,   # % of basic supply rate added as install labour
    "overhead_pct":    8.0,   # % of direct added as overhead (summed with profit)
    "profit_pct":     12.0,   # % of direct added as profit  (summed with overhead)
    "contingency_pct": 0.0,   # % risk reserve compounded after OH+P, before VAT
    "vat_pct":         0.0,   # % VAT applied as final layer
    # 2026-06-24 (Cost Estimate v3): client-facing Labour line at the
    # bottom of the table = materials_subtotal * labour_pct_client/100.
    # Cap 10..30. Separate from the engine-level `labour_pct` above.
    "labour_pct_client": 20.0,
}


def _ensure_bom_rates_table():
    """Idempotent — runs on both SQLite (dev) and Postgres (Render)."""
    if bool(os.environ.get("DATABASE_URL")):
        _ensure_marketplace_schema_postgres()
        # Postgres path: separately create the rates table since the
        # marketplace bootstrap above is one-shot at first marketplace hit.
        for ddl in [
            """CREATE TABLE IF NOT EXISTS marketplace_bom_rates (
                bom_id           INTEGER PRIMARY KEY,
                labour_pct       REAL DEFAULT 15,
                overhead_pct     REAL DEFAULT 8,
                profit_pct       REAL DEFAULT 12,
                contingency_pct  REAL DEFAULT 0,
                vat_pct          REAL DEFAULT 0,
                updated_at       TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )""",
            "ALTER TABLE marketplace_bom_rates ADD COLUMN IF NOT EXISTS contingency_pct REAL DEFAULT 0",
            "ALTER TABLE marketplace_bom_rates ADD COLUMN IF NOT EXISTS labour_pct_client REAL DEFAULT 20",
        ]:
            try:
                with get_db() as c:
                    c.execute(ddl)
            except Exception:
                pass
        return
    with get_db() as c:
        c.executescript(
            """
            CREATE TABLE IF NOT EXISTS marketplace_bom_rates (
                bom_id           INTEGER PRIMARY KEY,
                labour_pct       REAL DEFAULT 15,
                overhead_pct     REAL DEFAULT 8,
                profit_pct       REAL DEFAULT 12,
                contingency_pct  REAL DEFAULT 0,
                vat_pct          REAL DEFAULT 0,
                updated_at       TEXT DEFAULT CURRENT_TIMESTAMP
            );
            """
        )
        # SQLite-side idempotent ALTER for pre-Task-#4 DBs.
        try:
            c.execute("ALTER TABLE marketplace_bom_rates ADD COLUMN contingency_pct REAL DEFAULT 0")
        except Exception:
            pass
        # 2026-06-24 Cost Estimate v3: labour_pct_client (10..30).
        try:
            c.execute("ALTER TABLE marketplace_bom_rates ADD COLUMN labour_pct_client REAL DEFAULT 20")
        except Exception:
            pass


def _bom_rates_for(bom_id: int) -> dict:
    """Return the active rates for a BOM. Falls back to defaults if no
    row exists yet — never raises."""
    _ensure_bom_rates_table()
    try:
        with get_db() as c:
            row = c.execute(
                "SELECT labour_pct, overhead_pct, profit_pct, vat_pct, contingency_pct, labour_pct_client "
                "FROM marketplace_bom_rates WHERE bom_id=?", (bom_id,),
            ).fetchone()
    except Exception:
        # contingency_pct missing on pre-Task-#4 DBs -- retry without it.
        try:
            with get_db() as c:
                row = c.execute(
                    "SELECT labour_pct, overhead_pct, profit_pct, vat_pct "
                    "FROM marketplace_bom_rates WHERE bom_id=?", (bom_id,),
                ).fetchone()
        except Exception:
            row = None
    if row:
        # Postgres rows expose .keys(); SQLite Row objects do too.
        _keys = list(row.keys()) if hasattr(row, "keys") else []
        return {
            "labour_pct":      float(row["labour_pct"]   or 0),
            "overhead_pct":    float(row["overhead_pct"] or 0),
            "profit_pct":      float(row["profit_pct"]   or 0),
            "vat_pct":         float(row["vat_pct"]      or 0),
            "contingency_pct": float(row["contingency_pct"] or 0) if "contingency_pct" in _keys else 0.0,
            "labour_pct_client": (max(10.0, min(30.0, float(row["labour_pct_client"] or 20.0)))
                                  if "labour_pct_client" in _keys else 20.0),
        }
    return dict(_BOM_DEFAULT_RATES)


def _bom_totals_with_rates(items, rates: dict, fx_rate: float = 1.0) -> dict:
    """Additive rate build-up (2026-06-24 owner spec). Mirrors _boq_safe_rate.

    Per-line: if marketplace_bom_items.basic_price / supply_pct /
    profit_pct / install_pct / overhead_pct are set, those win.
    Otherwise fall back to the project-wide defaults in `rates`
    (the marketplace_bom_rates row).

    Compatibility: project-wide overhead_pct/profit_pct stay as-is.
    contingency_pct is re-purposed as the project-wide supply_pct
    default, vat_pct as the project-wide install_pct default — so
    the existing rows do not need migrating. labour_pct is ignored.

    Caps: supply 15, install 25, profit 5, overhead 15.
    """
    def _clamp(v, lo, hi):
        try:
            x = float(v or 0)
        except (TypeError, ValueError):
            x = 0.0
        return max(lo, min(hi, x))
    # Project-wide fallbacks (re-purposed columns -- see docstring).
    default_supply   = _clamp(rates.get("contingency_pct", 0), 0.0, 15.0)
    default_install  = _clamp(rates.get("vat_pct",         0), 0.0, 25.0)
    default_profit   = _clamp(rates.get("profit_pct",      0), 0.0,  5.0)
    default_overhead = _clamp(rates.get("overhead_pct",    0), 0.0, 15.0)

    def _row_val(it, key):
        try:
            keys = it.keys() if hasattr(it, "keys") else []
            if key in keys:
                v = it[key]
                return v if v is not None else None
        except Exception:
            pass
        return None

    lines = []
    cat_totals: dict = {}
    grand = 0.0
    for it in items:
        # Per-line basic_price wins; else unit_price_override; else catalog.
        line_basic = _row_val(it, "basic_price")
        if line_basic in (None, 0, 0.0):
            line_basic = it["unit_price_override"] if it["unit_price_override"] is not None else (it["catalog_price"] or 0)
        basic_rate = float(line_basic or 0) * float(fx_rate or 1.0)

        sp = _row_val(it, "supply_pct")
        ip = _row_val(it, "install_pct")
        pp = _row_val(it, "profit_pct")
        op = _row_val(it, "overhead_pct")
        sp = _clamp(sp, 0.0, 15.0) if sp not in (None, "") else default_supply
        ip = _clamp(ip, 0.0, 25.0) if ip not in (None, "") else default_install
        pp = _clamp(pp, 0.0,  5.0) if pp not in (None, "") else default_profit
        op = _clamp(op, 0.0, 15.0) if op not in (None, "") else default_overhead

        supply_amt   = basic_rate * sp / 100.0
        profit_amt   = basic_rate * pp / 100.0
        install_amt  = basic_rate * ip / 100.0
        overhead_amt = basic_rate * op / 100.0
        supply_disp  = supply_amt  + profit_amt
        install_disp = install_amt + overhead_amt
        total_rate   = basic_rate + supply_disp + install_disp
        qty          = float(it["qty"] or 0)
        line_total   = total_rate * qty
        cat = it["category_name"] or "Uncategorised"
        cat_totals[cat] = cat_totals.get(cat, 0) + line_total
        grand += line_total
        lines.append({
            "item": it,
            "basic_rate":     basic_rate,
            "supply_pct":     sp,
            "profit_pct":     pp,
            "install_pct":    ip,
            "overhead_pct":   op,
            "supply_amount":  supply_amt,
            "profit_amount":  profit_amt,
            "install_amount": install_amt,
            "overhead_amount": overhead_amt,
            "supply_disp":    supply_disp,
            "install_disp":   install_disp,
            "total_rate":     total_rate,
            "line_total":     line_total,
            # Back-compat aliases for older templates:
            "install_labour": 0.0,
            "overhead":       overhead_amt,
            "profit":         profit_amt,
            "contingency":    0.0,
            "vat":            0.0,
            "unit_price":     basic_rate,
        })
    return {
        "lines": lines,
        "category_totals": cat_totals,
        "grand_total": grand,
        "rates": rates,
        "totals_basic":    sum(l["basic_rate"]     * (l["item"]["qty"] or 0) for l in lines),
        "totals_supply":   sum(l["supply_disp"]    * (l["item"]["qty"] or 0) for l in lines),
        "totals_install":  sum(l["install_disp"]   * (l["item"]["qty"] or 0) for l in lines),
        # Back-compat aliases:
        "totals_labour":   0.0,
        "totals_overhead": sum(l["overhead_amount"] * (l["item"]["qty"] or 0) for l in lines),
        "totals_profit":   sum(l["profit_amount"]   * (l["item"]["qty"] or 0) for l in lines),
        "totals_vat":      0.0,
    }


# ──────────────────────── POST /boms/<id>/rates ─────────────────────────


@app.route("/boms/<int:bom_id>/rates", methods=["POST"])
@login_required
def boms_save_rates(bom_id):
    uid = session["user_id"]
    _bom_owned_or_404(bom_id, uid)
    csrf_protect()
    _ensure_bom_rates_table()
    f = request.form
    def _pct(name: str) -> float:
        try:
            v = float(f.get(name, _BOM_DEFAULT_RATES[name]))
        except (TypeError, ValueError):
            v = _BOM_DEFAULT_RATES[name]
        # Clamp to a sane window — protects the totals from a runaway 1e9 value.
        return max(0.0, min(100.0, v))
    lab, ovh, prf, cnt, vat = _pct("labour_pct"), _pct("overhead_pct"), _pct("profit_pct"), _pct("contingency_pct"), _pct("vat_pct")
    # 2026-06-24 Cost Estimate v3: client-facing labour line. Cap 10..30.
    try:
        _lab_c_raw = float(f.get("labour_pct_client", 20.0))
    except (TypeError, ValueError):
        _lab_c_raw = 20.0
    lab_client = max(10.0, min(30.0, _lab_c_raw))
    try:
        with get_db() as c:
            # UPSERT — INSERT OR REPLACE on SQLite; ON CONFLICT on Postgres
            try:
                c.execute(
                    "INSERT OR REPLACE INTO marketplace_bom_rates "
                    "(bom_id, labour_pct, overhead_pct, profit_pct, contingency_pct, vat_pct, labour_pct_client) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?)",
                    (bom_id, lab, ovh, prf, cnt, vat, lab_client),
                )
            except Exception:
                # Column not migrated yet: fall back to legacy 6-col upsert.
                c.execute(
                    "INSERT OR REPLACE INTO marketplace_bom_rates "
                    "(bom_id, labour_pct, overhead_pct, profit_pct, contingency_pct, vat_pct) "
                    "VALUES (?, ?, ?, ?, ?, ?)",
                    (bom_id, lab, ovh, prf, cnt, vat),
                )
            c.execute(
                "UPDATE marketplace_boms SET updated_at=CURRENT_TIMESTAMP WHERE id=?",
                (bom_id,),
            )
    except Exception as _e:
        try: app.logger.exception("boms_save_rates failed bom_id=%s: %s", bom_id, _e)
        except Exception: pass
        flash(f"Could not save rates: {_e!s}. The Cost Estimate is unchanged.", "danger")
        return redirect(url_for("boms_view", bom_id=bom_id))
    flash(f"Rates updated — labour {lab}% / overhead {ovh}% / profit {prf}% / contingency {cnt}% / VAT {vat}% / client labour {lab_client}%.", "success")
    return redirect(url_for("boms_view", bom_id=bom_id))


# ──────────────────────── GET /boms/<id>/boq.xlsx ────────────────────────


@app.route("/boms/<int:bom_id>/boq.xlsx")
@login_required
def boms_boq_xlsx(bom_id):
    uid = session["user_id"]
    bom = _bom_owned_or_404(bom_id, uid)
    items = _bom_items_with_prices(bom_id)
    rates = _bom_rates_for(bom_id)
    _bcur = (bom["currency"] if "currency" in bom.keys() and bom["currency"] else "GHS")
    _brate = _CURRENCY_RATES_FROM_USD.get(_bcur, 1.0)
    totals = _bom_totals_with_rates(items, rates, fx_rate=_brate)

    import openpyxl
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
    from openpyxl.utils import get_column_letter

    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "BOQ"

    bold = Font(bold=True)
    title_font = Font(bold=True, size=14, color="B45309")
    header_fill = PatternFill("solid", fgColor="1E3A5F")
    header_font = Font(bold=True, color="FFFFFF")
    cat_fill = PatternFill("solid", fgColor="FEF3C7")
    thin = Side(border_style="thin", color="D1D5DB")
    box = Border(left=thin, right=thin, top=thin, bottom=thin)

    # Phase 1 xlsx client-clean: default columns per master prompt s11.
    # Add ?include_buildup=1 to also emit a "Project Rate Build-Up" sheet.
    include_buildup = bool(request.args.get("include_buildup") == "1")
    if include_buildup:
        try:
            from new_boq_hierarchy_schema import boq_audit
            boq_audit(get_db, uid, "boq_exported_internal", "marketplace_bom", bom_id, "xlsx")
        except Exception:
            pass
    cur_code = (bom["currency"] if "currency" in bom.keys() and bom["currency"] else "GHS")

    # Title + meta (2026-06-24 v3: SolarPro Marketplace branding;
    # Brand/Company/Phone columns dropped per owner directive).
    ws["A1"] = "SolarPro Marketplace · Accra, Ghana"
    ws["A1"].font = Font(bold=True, size=12, color="1E3A5F")
    ws.merge_cells("A1:F1")
    ws["A2"] = f"Quick Cost Estimate (for Electricians) — {bom['title']}"
    ws["A2"].font = title_font
    ws.merge_cells("A2:F2")
    ws["A3"] = f"Project: {bom['project_name'] or '-'}"
    ws["A4"] = f"Client : {bom['client_name'] or '-'}"
    ws["A5"] = f"Date   : {bom['updated_at']}"

    # 2026-06-24 v3: 6-column body. Brand/Company/Phone dropped.
    headers = ["#", "Description", "Qty", "Unit",
               f"Basic Rate ({cur_code})", "Basic Rate (US$)"]
    HROW = 7  # shifted +1 to make room for the branding row in A1
    for col, h in enumerate(headers, 1):
        cell = ws.cell(row=HROW, column=col, value=h)
        cell.font = header_font
        cell.fill = header_fill
        cell.border = box
        cell.alignment = Alignment(horizontal="center")

    # Excel cell-content safety: prefix any leading '=' with apostrophe
    # so Excel doesn't try to evaluate user-supplied text as a formula.
    def _sanitize(v):
        s = str(v or "")
        return "'" + s if s and s[0] in ("=", "+", "-", "@") else s

    row = HROW + 1
    prev_cat = None
    for idx, line in enumerate(totals["lines"], 1):
        it = line["item"]
        cat = it["category_name"] or "Uncategorised"
        if cat != prev_cat:
            ws.cell(row=row, column=1, value=cat).font = bold
            ws.cell(row=row, column=1).fill = cat_fill
            ws.merge_cells(start_row=row, start_column=1, end_row=row, end_column=len(headers))
            row += 1
            prev_cat = cat
        _fx = float(_brate or 1.0)
        rate_local = float(line["total_rate"] or 0)
        rate_usd   = (rate_local / _fx) if _fx else 0.0
        # 2026-06-24 v3: Brand/Company/Phone columns dropped.
        ws.cell(row=row, column=1, value=idx)
        ws.cell(row=row, column=2, value=_sanitize(it["custom_name"]))
        ws.cell(row=row, column=3, value=float(it["qty"] or 0))
        ws.cell(row=row, column=4, value=_sanitize(it["unit"]))
        ws.cell(row=row, column=5, value=round(rate_local, 2))
        ws.cell(row=row, column=6, value=round(rate_usd, 2))
        for col in range(1, len(headers) + 1):
            ws.cell(row=row, column=col).border = box
        row += 1

    # Subtotals + materials total + labour line + grand total (6-col layout).
    row += 1
    for cat, sub in totals["category_totals"].items():
        ws.cell(row=row, column=2, value=f"{cat} subtotal (qty * rate, {cur_code})").font = bold
        ws.cell(row=row, column=5, value=round(sub, 2)).font = bold
        row += 1
    row += 1
    # 2026-06-24 v3: Materials subtotal + Labour cost + Grand Total.
    _mat_total   = float(totals.get("grand_total", 0) or 0)
    _lab_c_pct   = float(rates.get("labour_pct_client", 20.0) or 20.0)
    _lab_c_pct   = max(10.0, min(30.0, _lab_c_pct))
    _lab_c_amt   = _mat_total * _lab_c_pct / 100.0
    _final_total = _mat_total + _lab_c_amt
    ws.cell(row=row, column=2, value=f"Materials subtotal ({cur_code})").font = bold
    ws.cell(row=row, column=5, value=round(_mat_total, 2)).font = bold
    row += 1
    ws.cell(row=row, column=2, value=f"Labour cost — {_lab_c_pct:.0f}% of materials ({cur_code})").font = bold
    ws.cell(row=row, column=5, value=round(_lab_c_amt, 2)).font = bold
    row += 1
    ws.cell(row=row, column=2, value=f"GRAND TOTAL ({cur_code})").font = title_font
    ws.cell(row=row, column=5, value=round(_final_total, 2)).font = title_font
    row += 2
    ws.cell(row=row, column=2, value="SolarPro Marketplace · Accra, Ghana").font = Font(italic=True, color="9090B0")

    for col, w in enumerate([5, 38, 8, 8, 18, 18], 1):
        ws.column_dimensions[get_column_letter(col)].width = w

    if include_buildup:
        # Project Rate Build-Up sheet (master prompt s12). Stored
        # separate from the BOQ; client-facing export omits it.
        ws3 = wb.create_sheet("Project Rate Build-Up")
        ws3["A1"] = f"Project Rate Build-Up — {bom['title']}"
        ws3["A1"].font = title_font
        ws3.merge_cells("A1:L1")
        ws3["A2"] = "INTERNAL ONLY — do not share with client/tender."
        ws3["A2"].font = Font(bold=True, color="DC2626")
        ws3["A4"] = (
            f"Rates: labour {rates['labour_pct']}% · overhead {rates['overhead_pct']}% "
            f"· profit {rates['profit_pct']}% · VAT {rates['vat_pct']}%"
        )
        bu_headers = ["#", "Description", "Category", "Qty", "Unit",
                      f"Basic ({cur_code})", f"Supply ({cur_code})", f"Install ({cur_code})",
                      f"+OH ({cur_code})", f"+Profit ({cur_code})", f"+VAT ({cur_code})",
                      f"Final Rate ({cur_code})", f"Amount ({cur_code})"]
        HROW3 = 6
        for col, h in enumerate(bu_headers, 1):
            cell = ws3.cell(row=HROW3, column=col, value=h)
            cell.font = header_font
            cell.fill = header_fill
            cell.border = box
            cell.alignment = Alignment(horizontal="center")
        r3 = HROW3 + 1
        for idx, line in enumerate(totals["lines"], 1):
            it = line["item"]
            cat = it["category_name"] or "Uncategorised"
            ws3.cell(row=r3, column=1, value=idx)
            ws3.cell(row=r3, column=2, value=_sanitize(it["custom_name"]))
            ws3.cell(row=r3, column=3, value=_sanitize(cat))
            ws3.cell(row=r3, column=4, value=float(it["qty"] or 0))
            ws3.cell(row=r3, column=5, value=_sanitize(it["unit"]))
            ws3.cell(row=r3, column=6, value=round(line["basic_rate"], 2))
            ws3.cell(row=r3, column=7, value=round(line["basic_rate"], 2))
            ws3.cell(row=r3, column=8, value=round(line["install_labour"], 2))
            ws3.cell(row=r3, column=9, value=round(line["overhead"], 2))
            ws3.cell(row=r3, column=10, value=round(line["profit"], 2))
            ws3.cell(row=r3, column=11, value=round(line["vat"], 2))
            ws3.cell(row=r3, column=12, value=round(line["total_rate"], 2))
            ws3.cell(row=r3, column=13, value=round(line["line_total"], 2))
            r3 += 1
        for col, w in enumerate([5, 36, 18, 7, 7, 12, 12, 12, 10, 10, 10, 14, 14], 1):
            ws3.column_dimensions[get_column_letter(col)].width = w

    # Summary sheet
    ws2 = wb.create_sheet("Summary")
    ws2["A1"] = "Category"; ws2["B1"] = "Subtotal (USD)"
    ws2["A1"].font = bold; ws2["B1"].font = bold
    r2 = 2
    for cat, sub in totals["category_totals"].items():
        ws2.cell(row=r2, column=1, value=cat)
        ws2.cell(row=r2, column=2, value=round(sub, 2))
        r2 += 1
    ws2.cell(row=r2 + 1, column=1, value="GRAND TOTAL").font = bold
    ws2.cell(row=r2 + 1, column=2, value=round(totals["grand_total"], 2)).font = bold

    try:
        for _ws in wb.worksheets:
            _solarpro_xlsx_apply_borders_and_a4(_ws)
    except Exception:
        pass
    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    safe_title = re.sub(r"[^A-Za-z0-9_.-]+", "_", bom["title"])[:60]
    return send_file(
        buf,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        as_attachment=True,
        download_name=f"CostEstimate_{safe_title}.xlsx",
    )


# ──────────────────────── GET /boms/<id>/boq.pdf ─────────────────────────


@app.route("/boms/<int:bom_id>/boq.pdf")
@login_required
def boms_boq_pdf(bom_id):
    uid = session["user_id"]
    bom = _bom_owned_or_404(bom_id, uid)
    items = _bom_items_with_prices(bom_id)
    rates = _bom_rates_for(bom_id)
    _bcur = (bom["currency"] if "currency" in bom.keys() and bom["currency"] else "GHS")
    _brate = _CURRENCY_RATES_FROM_USD.get(_bcur, 1.0)
    totals = _bom_totals_with_rates(items, rates, fx_rate=_brate)

    include_buildup = bool(request.args.get("include_buildup") == "1")
    if include_buildup:
        try:
            from new_boq_hierarchy_schema import boq_audit
            boq_audit(get_db, uid, "boq_exported_internal", "marketplace_bom", bom_id, "pdf")
        except Exception:
            pass
    cur = (bom["currency"] if "currency" in bom.keys() and bom["currency"] else "GHS")
    md = []
    md.append("**SolarPro Marketplace · Accra, Ghana**  ")
    md.append("")
    md.append(f"# Quick Cost Estimate (for Electricians) — {bom['title']}" + (" (Internal Build-Up)" if include_buildup else ""))
    if bom["project_name"]:
        md.append(f"**Project:** {bom['project_name']}  ")
    if bom["client_name"]:
        md.append(f"**Client:** {bom['client_name']}  ")
    md.append(f"**Generated:** {bom['updated_at']}")
    md.append("")
    if include_buildup:
        md.append("## Rates applied (internal only)")
        md.append("")
        md.append(
            f"- Install labour: **{rates['labour_pct']}%** of basic supply\n"
            f"- Overhead: **{rates['overhead_pct']}%**\n"
            f"- Profit: **{rates['profit_pct']}%**\n"
            f"- VAT: **{rates['vat_pct']}%**\n"
        )
        md.append("")
    md.append("## Line items")
    md.append("")
    # Apinto / Agenda Commercial 9-column body (2026-06-22).
    _fx = float(_brate or 1.0) if '_brate' in dir() else float(rates.get('fx_rate', 1.0) or 1.0)
    # 2026-06-24 v3: 6-col table (Brand/Company/Phone dropped).
    md.append(f"| # | Description | Qty | Unit | Basic Rate ({cur}) | Basic Rate (US$) |")
    md.append("|---|---|---|---|---|---|")
    prev_cat = None
    for idx, line in enumerate(totals["lines"], 1):
        it = line["item"]
        cat = it["category_name"] or "Uncategorised"
        if cat != prev_cat:
            md.append(f"| | **{cat}** |  |  |  |  |")
            prev_cat = cat
        rate_local = float(line['total_rate'] or 0)
        rate_usd   = (rate_local / _fx) if _fx else 0.0
        md.append(
            f"| {idx} | {it['custom_name']} | {it['qty']:.2f} | {it['unit']} | "
            f"{rate_local:,.2f} | {rate_usd:,.2f} |"
        )
    if include_buildup:
        md.append("")
        md.append("## Internal rate build-up (do not share with client)")
        md.append("")
        md.append(f"| # | Description | Qty | Unit | Basic ({cur}) | +Labour ({cur}) | +OH ({cur}) | +Profit ({cur}) | +VAT ({cur}) | Final Rate ({cur}) | Amount ({cur}) |")
        md.append("|---|---|---|---|---|---|---|---|---|---|---|")
        for idx, line in enumerate(totals["lines"], 1):
            it = line["item"]
            md.append(
                f"| {idx} | {it['custom_name']} | {it['qty']:.2f} | {it['unit']} | "
                f"{line['basic_rate']:,.2f} | {line['install_labour']:,.2f} | "
                f"{line['overhead']:,.2f} | {line['profit']:,.2f} | {line['vat']:,.2f} | "
                f"{line['total_rate']:,.2f} | {line['line_total']:,.2f} |"
            )
    md.append("")
    md.append("## Category subtotals")
    md.append("")
    md.append(f"| Category | Subtotal ({cur}) |")
    md.append("|---|---|")
    for cat, sub in totals["category_totals"].items():
        md.append(f"| {cat} | {sub:.2f} |")
    md.append("")
    # 2026-06-24 v3: client-facing Labour line under Materials grand total.
    _materials_total = float(totals.get("grand_total", 0) or 0)
    _lab_client_pct = float(rates.get("labour_pct_client", 20.0) or 20.0)
    _lab_amt = _materials_total * _lab_client_pct / 100.0
    _final_total = _materials_total + _lab_amt
    md.append("")
    md.append("## Totals")
    md.append("")
    md.append(f"| Line | Amount ({cur}) |")
    md.append("|---|---|")
    md.append(f"| Materials subtotal | {_materials_total:,.2f} |")
    md.append(f"| Labour cost ({_lab_client_pct:.0f}% of materials) | {_lab_amt:,.2f} |")
    md.append(f"| **GRAND TOTAL** | **{_final_total:,.2f}** |")
    md.append("")

    safe_title = re.sub(r"[^A-Za-z0-9_.-]+", "_", bom["title"])[:60]
    return _render_pdf(
        f"Quick Cost Estimate — {bom['title']}",
        "\n".join(md),
        f"CostEstimate_{safe_title}.pdf",
    )


# ─── Routes — Procurement Center + Basic Price Sheet ──────────────────────────
# Slice 9: the user-facing "Procurement Center" entry point. After login the
# user lands on /procurement-center, searches catalog products, ticks the
# checkbox on each one they want, picks a currency + doc type (Basic Price
# Sheet / BOM / BOQ) from the left-side panel, and clicks Add. The chosen
# products land in a new document of the selected type, prices converted
# to the picked currency.
#
# Basic Price Sheet is new — it's a reference list with qty=1 per row and
# supplier contact details (name, brand, phone, email, address) so the
# estimator can call the supplier directly. BOM + BOQ reuse the existing
# Slice 5+8 surfaces.

def _fx_rate(code, default):
    """Read an indicative FX rate from env FX_<CODE>_PER_USD; fall back
    to the bundled default. Lets ops override the rate without a code push."""
    try:
        return float(os.environ.get(f"FX_{code}_PER_USD", default))
    except (TypeError, ValueError):
        return float(default)


_CURRENCY_RATES_FROM_USD = {
    # Indicative rates — overridable via FX_<CODE>_PER_USD env vars.
    # Customers see a disclaimer so they know to verify before quoting.
    # Refreshed 2026-06-25 from open.er-api.com (sensible 1-2 dp rounding).
    "USD": 1.0,
    "EUR": _fx_rate("EUR", 0.88),
    "GBP": _fx_rate("GBP", 0.76),
    "GHS": _fx_rate("GHS", 11.2),
    "NGN": _fx_rate("NGN", 1370.0),
    "KES": _fx_rate("KES", 129.0),
    "ZAR": _fx_rate("ZAR", 16.6),
    "XOF": _fx_rate("XOF", 580.0),
    "ZMW": _fx_rate("ZMW", 18.0),
}
_CURRENCY_RATES_AS_OF = os.environ.get("FX_RATES_AS_OF", "2026-06-25")


def _convert_from_usd(price_usd: float, currency: str) -> float:
    rate = _CURRENCY_RATES_FROM_USD.get(
        (currency or "USD").upper(), 1.0
    )
    return float(price_usd or 0) * float(rate or 1.0)


def _ensure_price_sheet_tables():
    """Idempotent — works on both SQLite (dev) and Postgres (Render)."""
    is_pg = bool(os.environ.get("DATABASE_URL"))
    if is_pg:
        for ddl in [
            """CREATE TABLE IF NOT EXISTS marketplace_price_sheets (
                id            SERIAL PRIMARY KEY,
                user_id       INTEGER NOT NULL,
                title         VARCHAR(300) NOT NULL,
                currency      VARCHAR(3) DEFAULT 'GHS',
                created_at    TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )""",
            "CREATE INDEX IF NOT EXISTS idx_marketplace_price_sheets_user ON marketplace_price_sheets(user_id)",
            """CREATE TABLE IF NOT EXISTS marketplace_price_sheet_items (
                id                 SERIAL PRIMARY KEY,
                sheet_id           INTEGER NOT NULL,
                product_id         INTEGER DEFAULT 0,
                custom_name        VARCHAR(300) NOT NULL,
                unit               VARCHAR(20) DEFAULT 'No.',
                price_at_add       REAL DEFAULT 0,
                supplier_name      VARCHAR(200) DEFAULT '',
                supplier_brand     VARCHAR(120) DEFAULT '',
                supplier_phone     VARCHAR(40) DEFAULT '',
                supplier_email     VARCHAR(200) DEFAULT '',
                supplier_address   TEXT DEFAULT '',
                created_at         TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )""",
            "CREATE INDEX IF NOT EXISTS idx_marketplace_price_sheet_items_sheet ON marketplace_price_sheet_items(sheet_id)",
        ]:
            try:
                with get_db() as c:
                    c.execute(ddl)
            except Exception:
                pass
        return
    with get_db() as c:
        c.executescript("""
            CREATE TABLE IF NOT EXISTS marketplace_price_sheets (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id       INTEGER NOT NULL,
                title         TEXT NOT NULL,
                currency      TEXT DEFAULT 'GHS',
                created_at    TEXT DEFAULT CURRENT_TIMESTAMP,
                updated_at    TEXT DEFAULT CURRENT_TIMESTAMP
            );
            CREATE INDEX IF NOT EXISTS idx_marketplace_price_sheets_user
                ON marketplace_price_sheets(user_id);
            CREATE TABLE IF NOT EXISTS marketplace_price_sheet_items (
                id                INTEGER PRIMARY KEY AUTOINCREMENT,
                sheet_id          INTEGER NOT NULL,
                product_id        INTEGER DEFAULT 0,
                custom_name       TEXT NOT NULL,
                unit              TEXT DEFAULT 'No.',
                price_at_add      REAL DEFAULT 0,
                supplier_name     TEXT DEFAULT '',
                supplier_brand    TEXT DEFAULT '',
                supplier_phone    TEXT DEFAULT '',
                supplier_email    TEXT DEFAULT '',
                supplier_address  TEXT DEFAULT '',
                created_at        TEXT DEFAULT CURRENT_TIMESTAMP
            );
            CREATE INDEX IF NOT EXISTS idx_marketplace_price_sheet_items_sheet
                ON marketplace_price_sheet_items(sheet_id);
        """)


def _price_sheet_owned_or_404(sheet_id: int, user_id: int):
    with get_db() as c:
        row = c.execute(
            "SELECT * FROM marketplace_price_sheets WHERE id=? AND user_id=?",
            (sheet_id, user_id),
        ).fetchone()
    if not row:
        abort(404)
    return row


# ──────────────────────── GET /procurement-center ───────────────────────


@app.route("/procurement-center")
@login_required
def procurement_center():
    _ensure_marketplace_tables()
    _ensure_supplier_schema()
    _ensure_price_sheet_tables()
    q = (request.args.get("q") or "").strip()
    cat_id = _safe_int(request.args.get("cat"), 0)
    currency = (request.args.get("currency") or "GHS").strip().upper()
    if currency not in _CURRENCY_RATES_FROM_USD:
        currency = "GHS"

    with get_db() as c:
        categories = c.execute(
            "SELECT id, name, icon, "
            "  (SELECT COUNT(*) FROM equipment_catalog ec "
            "   WHERE ec.category_id=pc.id AND ec.is_active=1 "
            "         AND ec.is_public_visible=1 AND ec.is_verified=1) AS n "
            "FROM product_categories pc WHERE pc.is_active=1 "
            "ORDER BY pc.display_order"
        ).fetchall()

        sql = (
            "SELECT ec.id, ec.name, ec.brand, ec.model, ec.spec, ec.unit, "
            "       ec.price_usd, ec.lead_time_days, ec.category_id, "
            "       ec.literature_url, ec.datasheet_url, "
            "       s.name AS supplier_name, s.country AS supplier_country, "
            "       s.phone AS supplier_phone, s.email AS supplier_email, "
            "       pc.name AS category_name, pc.icon AS category_icon "
            "FROM equipment_catalog ec "
            "LEFT JOIN suppliers s ON s.id=ec.supplier_id "
            "LEFT JOIN product_categories pc ON pc.id=ec.category_id "
            "WHERE ec.is_active=1 AND ec.is_public_visible=1 AND ec.is_verified=1   AND ec.name NOT LIKE 'BulkProd-%'   AND ec.name NOT LIKE 'ProdB %'   AND ec.name NOT LIKE 'TestProd%'   AND ec.name NOT LIKE 'AUTOTEST%' "
        )
        args = []
        if cat_id:
            sql += "AND ec.category_id=? "
            args.append(cat_id)
        if q:
            like = f"%{q.lower()}%"
            sql += ("AND (LOWER(ec.name) LIKE ? OR LOWER(ec.brand) LIKE ? "
                    "     OR LOWER(ec.model) LIKE ? OR LOWER(ec.spec) LIKE ?) ")
            args.extend([like, like, like, like])
        # 2026-06-22 (session B): admin-tunable pagination.
        _ppp = _products_per_page()
        try: _page = max(1, int(request.args.get("page") or 1))
        except (TypeError, ValueError): _page = 1
        _offset = (_page - 1) * _ppp
        _count_sql = sql.replace(
            "SELECT ec.id, ec.name, ec.brand, ec.model, ec.spec, ec.unit,        ec.price_usd, ec.lead_time_days, ec.category_id,        ec.literature_url, ec.datasheet_url,        s.name AS supplier_name, s.country AS supplier_country,        s.phone AS supplier_phone, s.email AS supplier_email,        pc.name AS category_name, pc.icon AS category_icon ", "SELECT COUNT(*) "
        )
        try:
            _filter_count = c.execute(_count_sql, args).fetchone()[0]
        except Exception:
            _filter_count = 0
        _total_pages = max(1, (int(_filter_count) + _ppp - 1) // _ppp)
        if _page > _total_pages:
            _page = _total_pages
            _offset = (_page - 1) * _ppp
        sql += "ORDER BY ec.created_at DESC LIMIT ? OFFSET ?"
        products = c.execute(sql, args + [_ppp, _offset]).fetchall()

    # Pre-compute per-product converted price for the template.
    rate = _CURRENCY_RATES_FROM_USD.get(currency, 1.0)
    products_view = []
    for p in products:
        d = dict(p)
        d["price_in_currency"] = float(d["price_usd"] or 0) * rate
        products_view.append(d)
    # Group products by category -- matches the marketplace_public layout.
    products_by_category = []
    _seen_cat_ids = set()
    for cat in categories:
        prods = [pv for pv in products_view if pv.get("category_id") == cat["id"]]
        if prods:
            products_by_category.append({
                "category": cat,
                "products": prods,
            })
            _seen_cat_ids.add(cat["id"])
    orphans = [pv for pv in products_view
               if pv.get("category_id") not in _seen_cat_ids]
    if orphans:
        products_by_category.append({
            "category": {"id": 0, "name": "Uncategorised", "icon": "bi-box"},
            "products": orphans,
        })

    return render_template(
        "procurement_center.html",
        user=current_user(),
        categories=categories,
        products=products_view,
        products_by_category=products_by_category,
        selected_cat=cat_id,
        q=q,
        currency=currency,
        currencies=list(_CURRENCY_RATES_FROM_USD.keys()),
        rates_as_of=_CURRENCY_RATES_AS_OF,
        page=_page, total_pages=_total_pages, products_per_page=_ppp,
        filter_count=_filter_count,
    )


# ──────────────────────── POST /procurement-center/add ──────────────────


@app.route("/procurement-center/add", methods=["POST"])
@login_required
def procurement_center_add():
    """Take the checked product IDs from the form + the chosen doc type
    + currency, and create the new doc populated with those products.

    2026-06-22 (session B): also accept `stored_ids` (CSV from the
    sessionStorage layer) so paginated selections aren't lost when the
    user clicks Add on a later page.
    """
    csrf_protect()
    # Merge form checkboxes + persisted sessionStorage IDs.
    try:
        _stored = (request.form.get("stored_ids") or "").strip()
        _extra = [s for s in _stored.split(",") if s.strip().isdigit()]
        if _extra:
            _form_list = list(request.form.getlist("product_ids"))
            _merged = list(dict.fromkeys(_form_list + _extra))  # de-dup, keep order
            # Inject into request.form's getlist by adding to a ImmutableMultiDict copy.
            try:
                from werkzeug.datastructures import ImmutableMultiDict
                pairs = list(request.form.items(multi=True))
                pairs = [(k, v) for k, v in pairs if k != "product_ids"]
                pairs += [("product_ids", str(x)) for x in _merged]
                request.form = ImmutableMultiDict(pairs)
            except Exception:
                pass
    except Exception:
        pass
    _ensure_marketplace_tables()
    _ensure_supplier_schema()
    _ensure_bom_tables()
    _ensure_price_sheet_tables()
    uid = session["user_id"]

    doc_type = (request.form.get("doc_type") or "").strip()
    currency = (request.form.get("currency") or "GHS").strip().upper()
    if currency not in _CURRENCY_RATES_FROM_USD:
        currency = "GHS"
    if doc_type not in ("price_sheet", "bom", "boq"):
        flash("Choose a document type (Basic Price Sheet, BOM, or BOQ).", "danger")
        return redirect(url_for("procurement_center"))

    raw_pids = request.form.getlist("product_ids")
    pids = [int(x) for x in raw_pids if x.isdigit()]
    if not pids:
        flash("Tick at least one product on the grid before clicking Add.", "danger")
        return redirect(url_for("procurement_center"))

    # Fetch the selected products + supplier contact in one query.
    with get_db() as c:
        placeholders = ",".join(["?"] * len(pids))
        rows = c.execute(
            f"SELECT ec.id, ec.name, ec.brand, ec.model, ec.spec, ec.unit, "
            f"       ec.price_usd, "
            f"       s.name AS supplier_name, s.phone AS supplier_phone, "
            f"       s.email AS supplier_email, s.address AS supplier_address "
            f"FROM equipment_catalog ec "
            f"LEFT JOIN suppliers s ON s.id=ec.supplier_id "
            f"WHERE ec.id IN ({placeholders}) "
            f"  AND ec.is_active=1 AND ec.is_public_visible=1 AND ec.is_verified=1",
            pids,
        ).fetchall()

    if not rows:
        flash("None of the selected products are available.", "danger")
        return redirect(url_for("procurement_center"))

    rate = _CURRENCY_RATES_FROM_USD.get(currency, 1.0)
    today = datetime.now().strftime("%Y-%m-%d")

    if doc_type == "price_sheet":
        with get_db() as c:
            cur = c.execute(
                "INSERT INTO marketplace_price_sheets (user_id, title, currency) "
                "VALUES (?, ?, ?)",
                (uid, f"Price Sheet — {today}", currency),
            )
            sheet_id = cur.lastrowid
            for r in rows:
                price_in_currency = float(r["price_usd"] or 0) * rate
                c.execute(
                    "INSERT INTO marketplace_price_sheet_items "
                    "(sheet_id, product_id, custom_name, unit, price_at_add, "
                    " supplier_name, supplier_brand, supplier_phone, "
                    " supplier_email, supplier_address) "
                    "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
                    (
                        sheet_id, r["id"], r["name"], r["unit"] or "No.",
                        round(price_in_currency, 2),
                        r["supplier_name"] or "",
                        r["brand"] or "",
                        r["supplier_phone"] or "",
                        r["supplier_email"] or "",
                        r["supplier_address"] or "",
                    ),
                )
        flash(
            f"Basic Price Sheet created with {len(rows)} item"
            f"{'s' if len(rows) != 1 else ''} in {currency}.", "success",
        )
        return redirect(url_for("price_sheet_view", sheet_id=sheet_id))

    if doc_type == "bom":
        with get_db() as c:
            cur = c.execute(
                "INSERT INTO marketplace_boms (user_id, title, currency) VALUES (?, ?, ?)",
                (uid, f"BOM — {today}", currency),
            )
            bom_id = cur.lastrowid
            for r in rows:
                c.execute(
                    "INSERT INTO marketplace_bom_items "
                    "(bom_id, product_id, custom_name, qty, unit) "
                    "VALUES (?, ?, ?, ?, ?)",
                    (bom_id, r["id"], r["name"], 1, r["unit"] or "No."),
                )
        flash(f"BOM created with {len(rows)} item{'s' if len(rows) != 1 else ''}.", "success")
        return redirect(url_for("boms_view", bom_id=bom_id))

    # doc_type == "boq" — same as BOM today since the BOQ is a printable
    # view of a BOM. Land them in the BOM editor; they then click View BOQ
    # / Excel / PDF from there.
    with get_db() as c:
        cur = c.execute(
            "INSERT INTO marketplace_boms (user_id, title, currency) VALUES (?, ?, ?)",
            (uid, f"BOQ — {today}", currency),
        )
        bom_id = cur.lastrowid
        for r in rows:
            c.execute(
                "INSERT INTO marketplace_bom_items "
                "(bom_id, product_id, custom_name, qty, unit) "
                "VALUES (?, ?, ?, ?, ?)",
                (bom_id, r["id"], r["name"], 1, r["unit"] or "No."),
            )
    flash(
        f"BOQ draft created with {len(rows)} item"
        f"{'s' if len(rows) != 1 else ''}. Set quantities + rates, then view the BOQ.",
        "success",
    )
    return redirect(url_for("boms_view", bom_id=bom_id))


