# ─── Routes — Supplier product Edit + Delete (scope tightening) ──────────────
# User-confirmed scope 2026-06-18: "supplier add and edit their products only
# and respond to rfq". Slice 2 already shipped ADD via /supplier/products/add
# and the RFQ response surface is at /supplier/rfqs/<id>. This module adds the
# missing EDIT + DELETE actions for products the supplier already owns.
#
# Authorisation: every action checks (supplier_id == _current_supplier().id).
# Suppliers can NEVER touch a product owned by another supplier.
# Delete is SOFT (is_active=0) so the product disappears from the marketplace
# but historical BOM/BOQ references survive.


def _supplier_product_owned_or_404(pid: int):
    """Return the equipment_catalog row IFF it belongs to the current supplier
    (the logged-in supplier_admin user's own supplier). 404 otherwise."""
    s = _current_supplier()
    if not s:
        abort(404)
    with get_db() as c:
        row = c.execute(
            "SELECT * FROM equipment_catalog WHERE id=? AND supplier_id=?",
            (pid, s["id"]),
        ).fetchone()
    if not row:
        abort(404)
    return row, s


@app.route("/supplier/products/<int:pid>/edit", methods=["GET", "POST"])
@supplier_required
def supplier_product_edit(pid):
    """Supplier edits one of their own products. Name, brand, model, spec,
    unit, price, lead time, category, subcategory are mutable. Edits drop the
    is_verified flag back to 0 so the admin must re-approve material changes
    before the new values are published on the public marketplace."""
    row, s = _supplier_product_owned_or_404(pid)
    with get_db() as c:
        categories = c.execute(
            "SELECT id, name FROM product_categories "
            "WHERE is_active=1 ORDER BY display_order"
        ).fetchall()
    if request.method == "GET":
        return render_template(
            "supplier_product_edit.html",
            user=current_user(),
            supplier=s,
            product=row,
            categories=categories,
            brands=_get_active_brands(),
        )
    csrf_protect()
    f = request.form
    name = (f.get("name") or "").strip()
    if not name:
        flash("Product name is required.", "danger")
        return redirect(url_for("supplier_product_edit", pid=pid))
    cat_id = _safe_int(f.get("category_id"), 0)
    with get_db() as c:
        cat_row = c.execute(
            "SELECT name FROM product_categories WHERE id=?", (cat_id,)
        ).fetchone()
        cat_label = cat_row["name"] if cat_row else (row["category"] or "")
        c.execute(
            "UPDATE equipment_catalog SET "
            "  name=?, brand=?, model=?, spec=?, unit=?, "
            "  price_usd=?, lead_time_days=?, "
            "  category_id=?, category=?, subcategory=?, "
            "  voltage_v=?, frequency_hz=?, compliance_standards=?, "
            "  is_verified=0 "
            "WHERE id=? AND supplier_id=?",
            (
                name,
                (f.get("brand") or "").strip(),
                (f.get("model") or "").strip(),
                (f.get("spec") or "").strip(),
                (f.get("unit") or "No.").strip(),
                _safe_int(f.get("price_usd"), 0),
                _safe_int(f.get("lead_time_days"), 30),
                cat_id,
                cat_label,
                (f.get("subcategory") or "").strip(),
                _safe_float(f.get("voltage_v"), 0),
                _safe_float(f.get("frequency_hz"), 0),
                (f.get("compliance_standards") or "").strip(),
                pid,
                s["id"],
            ),
        )
    flash(
        f"Saved changes to '{name}'. Your edits will appear on the public "
        f"marketplace after admin re-verification.",
        "success",
    )
    return redirect(url_for("supplier_products"))


@app.route("/supplier/products/<int:pid>/delete", methods=["POST"])
@supplier_required
def supplier_product_delete(pid):
    """Soft-delete (is_active=0) so the product drops out of the marketplace
    immediately but historical BOM/BOQ references stay intact."""
    csrf_protect()
    row, s = _supplier_product_owned_or_404(pid)
    with get_db() as c:
        c.execute(
            "UPDATE equipment_catalog SET is_active=0 "
            "WHERE id=? AND supplier_id=?",
            (pid, s["id"]),
        )
    flash(f"Removed '{row['name']}' from your catalog.", "success")
    return redirect(url_for("supplier_products"))

# ─── Routes — Technical Support Role (installation-staff assignments) ─────────
# Parallel to procurement_specialist (Slice 7). Admin promotes any solar user
# into role='technical_support'. Technical-support staff can review approved
# installers and the queue of completed designs that may need install dispatch.
# Admin still owns the promote/demote action.


def tech_support_role_required(f):
    """Decorator: allows is_admin=1 OR role='technical_support'.
    Anonymous → /login. Authenticated-but-wrong-role → 403."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if "user_id" not in session:
            return redirect(url_for("login"))
        u = current_user()
        if not u:
            return redirect(url_for("login"))
        if u["is_admin"]:
            return f(*args, **kwargs)
        if (u["role"] or "") == "technical_support":
            return f(*args, **kwargs)
        abort(403)
    return decorated


@app.route("/admin/marketplace/staff/<int:uid>/promote-tech-support", methods=["POST"])
@admin_required
def admin_marketplace_promote_tech_support(uid):
    csrf_protect()
    with get_db() as c:
        row = c.execute("SELECT id, username, role FROM users WHERE id=?", (uid,)).fetchone()
        if not row:
            abort(404)
        if (row["role"] or "") == "supplier_admin":
            flash("Cannot elect a supplier_admin as technical support — "
                  "demote them from supplier_admin first.", "danger")
            return redirect(url_for("admin_marketplace_staff"))
        c.execute("UPDATE users SET role='technical_support' WHERE id=?", (uid,))
    try:
        _log_marketplace_action(
            "promote_tech_support", "user", uid,
            f"{row['username']} (was role='{row['role'] or ''}')"
        )
    except Exception:
        pass
    flash(f"Elected '{row['username']}' as technical support for installation staff assignments.", "success")
    return redirect(url_for("admin_marketplace_staff"))


@app.route("/admin/marketplace/staff/<int:uid>/demote-tech-support", methods=["POST"])
@admin_required
def admin_marketplace_demote_tech_support(uid):
    csrf_protect()
    with get_db() as c:
        row = c.execute("SELECT id, username, role FROM users WHERE id=?", (uid,)).fetchone()
        if not row:
            abort(404)
        if (row["role"] or "") != "technical_support":
            flash("User is not currently technical support.", "warning")
            return redirect(url_for("admin_marketplace_staff"))
        c.execute("UPDATE users SET role='' WHERE id=?", (uid,))
    try:
        _log_marketplace_action("demote_tech_support", "user", uid, row["username"])
    except Exception:
        pass
    flash(f"Removed technical-support role from '{row['username']}'.", "success")
    return redirect(url_for("admin_marketplace_staff"))


@app.route("/installation-support")
@tech_support_role_required
def support_dashboard():
    """Technical-support landing — approved installers + designs awaiting
    install dispatch. Admins can view too (decorator allows is_admin)."""
    with get_db() as c:
        approved_installers = c.execute(
            "SELECT id, company_name, contact_name, email, phone, country, "
            "       regions, years_exp, staff_count, specialties, max_project_kw, "
            "       ai_grade, created_at "
            "FROM installers WHERE status='approved' "
            "ORDER BY created_at DESC LIMIT 100"
        ).fetchall()
        pending_installers = c.execute(
            "SELECT COUNT(*) FROM installers WHERE status='pending'"
        ).fetchone()[0]
        # Completed-design queue (stage='results' means the design is finalised
        # and the project is ready to be handed to an installer). LIMIT 50 so
        # the page stays snappy even when the queue grows.
        ready_for_dispatch = c.execute(
            "SELECT p.id, p.name AS project_name, p.updated_at, "
            "       u.username AS owner "
            "FROM projects p LEFT JOIN users u ON u.id=p.user_id "
            "WHERE p.stage='results' "
            "ORDER BY p.updated_at DESC LIMIT 50"
        ).fetchall()
    return render_template(
        "support_dashboard.html",
        user=current_user(),
        approved_installers=approved_installers,
        pending_installers=pending_installers,
        ready_for_dispatch=ready_for_dispatch,
    )


