@app.route("/boq-projects/new", methods=["GET", "POST"])
@login_required
def boq_projects_new():
    uid = session["user_id"]
    _boq_ensure_schema()
    # 2026-06-22 services: make sure services_csv column exists on every engine.
    for _ddl in (
        "ALTER TABLE boq_projects ADD COLUMN services_csv TEXT DEFAULT ''",
    ):
        try:
            with get_db() as _c:
                _c.execute(_ddl)
        except Exception:
            pass
    if request.method == "POST":
        csrf_protect()
        f = request.form
        name = (f.get("project_name") or "").strip()[:300]
        client = (f.get("client_name") or "").strip()[:300]
        location = (f.get("location") or "").strip()[:300]
        ptype = (f.get("project_type") or "single_building").strip()
        ext_works = 1 if f.get("external_works_included") else 0
        infra = 1 if f.get("infrastructure_included") else 0
        # 2026-06-22 services step: persist selected codes (csv)
        _chosen_services = [c for c in (f.getlist("services") or []) if c in _BOQ_SERVICE_LABEL]
        services_csv = ",".join(_chosen_services)
        if not name:
            flash("Project name is required.", "warning")
            return redirect(url_for("boq_projects_new"))
        if not _chosen_services:
            flash("Select at least one service the BOQ must cover.", "warning")
            return redirect(url_for("boq_projects_new"))
        with get_db() as c:
            # services_csv column was ALTERed in (1); on a fresh DB it's part of the schema.
            try:
                cur = c.execute(
                    "INSERT INTO boq_projects (user_id, project_name, client_name, "
                    "location, project_type, external_works_included, infrastructure_included, services_csv) "
                    "VALUES (?,?,?,?,?,?,?,?)",
                    (uid, name, client, location, ptype, ext_works, infra, services_csv),
                )
            except Exception:
                cur = c.execute(
                    "INSERT INTO boq_projects (user_id, project_name, client_name, "
                    "location, project_type, external_works_included, infrastructure_included) "
                    "VALUES (?,?,?,?,?,?,?)",
                    (uid, name, client, location, ptype, ext_works, infra),
                )
            pid = int(cur.lastrowid or 0)
        try:
            from new_boq_hierarchy_schema import boq_audit
            boq_audit(get_db, uid, "boq_project_created", "boq_project", pid)
        except Exception:
            pass
        return redirect(url_for("boq_building_new", pid=pid))
    # 2026-06-29 v3: pass the section skeleton as JSON so the form
    # preview renders client-side without an ajax round-trip.
    import json as _json
    _svc_sections = {
        code: {
            "name": skel["name"],
            "sections": [
                {"letter": s["letter"], "title": s["title"], "subsection": s.get("subsection", "")}
                for s in skel.get("sections", [])
            ],
        }
        for code, skel in _BOQ_SERVICE_BILL_SKELETON.items()
    }
    return render_template("boq_project_new.html",
                           user=current_user(),
                           services=_BOQ_SERVICES,
                           service_sections_json=_json.dumps(_svc_sections))


