# new_boq_project_edit_delete_routes.py
# Project-level Edit / Delete / Start-all-over routes.
#
# These three actions were missing -- once a project was created the
# owner had no way to rename it, clear its items, or get rid of it
# entirely. This file adds:
#
#   GET  /boq-projects/<pid>/edit   -- edit form (name / client / location / project_type)
#   POST /boq-projects/<pid>/edit   -- save changes
#   POST /boq-projects/<pid>/reset  -- clear all line items + rate-buildup rows
#                                      across the project (keeps buildings + floors)
#   POST /boq-projects/<pid>/delete -- delete the project + cascade everything
#
# All three enforce ownership through _boq_project_owned_or_404.


@app.route("/boq-projects/<int:pid>/edit", methods=["GET", "POST"])
@login_required
def boq_project_edit(pid):
    uid = session["user_id"]
    project = _boq_project_owned_or_404(pid, uid)
    if request.method == "POST":
        csrf_protect()
        f = request.form
        name = (f.get("project_name") or "").strip()[:300]
        client = (f.get("client_name") or "").strip()[:300]
        location = (f.get("location") or "").strip()[:300]
        ptype = (f.get("project_type") or "single_building").strip()
        ext_works = 1 if f.get("external_works_included") else 0
        infra = 1 if f.get("infrastructure_included") else 0
        # 2026-06-29 v3: Service Configuration + Build Mode editing.
        new_services = [c for c in (f.getlist("services") or []) if c in _BOQ_SERVICE_LABEL]
        new_services_csv = ",".join(new_services)
        new_build_mode = (f.get("build_mode") or "complete_boq").strip().lower()
        if new_build_mode not in ("section_by_section", "complete_boq"):
            new_build_mode = "complete_boq"
        remove_orphans = (f.get("remove_sections") or "").strip().lower() == "yes"
        if not name:
            flash("Project name is required.", "warning")
            return redirect(url_for("boq_project_edit", pid=pid))
        # Compute removed services so we can audit + (optionally) delete their bill rows.
        prev_services = _services_csv_to_list(project["services_csv"] or "")
        removed = [s for s in prev_services if s not in new_services]
        with get_db() as c:
            c.execute(
                "UPDATE boq_projects SET project_name=?, client_name=?, location=?, "
                "project_type=?, external_works_included=?, infrastructure_included=?, "
                "services_csv=?, build_mode=?, "
                "updated_at=CURRENT_TIMESTAMP WHERE id=? AND user_id=?",
                (name, client, location, ptype, ext_works, infra,
                 new_services_csv, new_build_mode, pid, uid),
            )
            n_deleted = 0
            if removed and remove_orphans:
                # Delete only items+rate rows tagged with one of the removed service codes.
                # Legacy items have service_code='' and are NEVER deleted here.
                placeholders = ",".join(["?"] * len(removed))
                # Rate-buildup rows first so the FK chain works on engines without ON DELETE CASCADE enforcement.
                c.execute(
                    f"DELETE FROM boq_floor_rate_buildup WHERE floor_item_id IN ("
                    f"  SELECT id FROM boq_floor_items WHERE project_id = ? AND service_code IN ({placeholders})"
                    f")",
                    (pid, *removed),
                )
                cur = c.execute(
                    f"DELETE FROM boq_floor_items WHERE project_id = ? AND service_code IN ({placeholders})",
                    (pid, *removed),
                )
                try:
                    n_deleted = cur.rowcount or 0
                except Exception:
                    n_deleted = 0
        try:
            from new_boq_hierarchy_schema import boq_audit
            boq_audit(get_db, uid, "boq_project_edited", "boq_project", pid,
                      f"services={new_services_csv} mode={new_build_mode} removed={removed} deleted_items={n_deleted}")
        except Exception:
            pass
        if removed and remove_orphans and n_deleted:
            flash(f"Project '{name}' updated. Removed {n_deleted} BOQ item(s) tied to dropped services.", "success")
        else:
            flash(f"Project '{name}' updated.", "success")
        return redirect(url_for("boq_project_overview", pid=pid))
    import json as _json
    _chosen = _services_csv_to_list(project["services_csv"] or "")
    _svc_sections = {
        code: {
            "name": skel["name"],
            "sections": [
                {"letter": s["letter"], "title": s["title"], "subsection": s.get("subsection", "")}
                for s in skel.get("sections", [])
            ],
        }
        for code, skel in _BOQ_SERVICE_BILL_SKELETON.items()
    }
    return render_template(
        "boq_project_edit.html",
        user=current_user(),
        project=project,
        services=_BOQ_SERVICES,
        chosen_services=_chosen,
        service_sections_json=_json.dumps(_svc_sections),
        service_labels_json=_json.dumps(_BOQ_SERVICE_LABEL),
    )


@app.route("/boq-projects/<int:pid>/recalc", methods=["POST"])
@login_required
def boq_project_recalc(pid):
    """Recompute total_amount + final_built_up_rate for every item in
    the project using the markup-only rate engine (boq_rate_v3.boq_rate_v3,
    single source of truth -- 2026-06-29 unification).

    Idempotent. Reads basic/supply%/install%/oh%/prf%/vat% from
    boq_floor_rate_buildup, calls _boq_safe_rate (a thin wrapper around
    boq_rate_v3), writes the new final_built_up_rate + total_amount back
    to BOTH boq_floor_items and boq_floor_rate_buildup. Flashes count
    + old vs new grand total so the owner sees the delta.
    """
    uid = session["user_id"]
    project = _boq_project_owned_or_404(pid, uid)
    csrf_protect()
    confirm = (request.form.get("confirm") or "").strip()
    if confirm != "RECALC":
        flash("Type RECALC to confirm recomputing all rates.", "warning")
        return redirect(url_for("boq_project_overview", pid=pid))
    updated = 0
    old_grand = 0.0
    new_grand = 0.0
    with get_db() as c:
        rows = c.execute(
            "SELECT i.id AS item_id, i.qty, i.total_amount AS old_total, "
            "       rb.basic_price, rb.supply_pct, rb.install_pct, "
            "       rb.overhead_pct, rb.profit_pct, "
            "       rb.vat_pct, rb.vat_in_basic "
            "FROM boq_floor_items i "
            "LEFT JOIN boq_floor_rate_buildup rb ON rb.floor_item_id=i.id "
            "WHERE i.project_id=?",
            (pid,),
        ).fetchall()
        for r in rows:
            qty = float(r["qty"] or 0)
            old_total = float(r["old_total"] or 0)
            old_grand += old_total
            # 2026-06-28 v3 spec: supply/install are PERCENTAGES; no contingency.
            new_rate = _boq_safe_rate(
                r["basic_price"], r["supply_pct"], r["install_pct"],
                r["overhead_pct"], r["profit_pct"],
                0, r["vat_pct"],
                vat_in_basic=bool(r["vat_in_basic"]),
            )
            new_total = qty * new_rate
            new_grand += new_total
            c.execute(
                "UPDATE boq_floor_items SET final_built_up_rate=?, "
                "       total_amount=? WHERE id=?",
                (new_rate, new_total, r["item_id"]),
            )
            c.execute(
                "UPDATE boq_floor_rate_buildup SET final_built_up_rate=?, "
                "       total_amount=? WHERE floor_item_id=?",
                (new_rate, new_total, r["item_id"]),
            )
            updated += 1
        c.execute(
            "UPDATE boq_projects SET updated_at=CURRENT_TIMESTAMP WHERE id=?",
            (pid,),
        )
    try:
        from new_boq_hierarchy_schema import boq_audit
        boq_audit(get_db, uid, "boq_project_recalc", "boq_project", pid,
                  "items=" + str(updated) + " old_grand=" + str(round(old_grand, 2))
                  + " new_grand=" + str(round(new_grand, 2)))
    except Exception:
        pass
    delta = new_grand - old_grand
    sign = "+" if delta >= 0 else ""
    flash(
        "Recalculated " + str(updated) + " item(s). "
        "Grand total " + str(round(old_grand, 2)) + " -> "
        + str(round(new_grand, 2)) + " (" + sign + str(round(delta, 2)) + ")."
        " Using markup-only rate engine (boq_rate_v3).",
        "success",
    )
    return redirect(url_for("boq_project_overview", pid=pid))


@app.route("/boq-projects/<int:pid>/reset", methods=["POST"])
@login_required
def boq_project_reset(pid):
    """Start all over -- delete every line item + rate-buildup row in the
    project but KEEP the project, buildings and floors. Owner can then
    re-pick templates / re-add items from scratch."""
    uid = session["user_id"]
    project = _boq_project_owned_or_404(pid, uid)
    csrf_protect()
    confirm = (request.form.get("confirm") or "").strip()
    if confirm != "RESET":
        flash("Type RESET to confirm starting over.", "warning")
        return redirect(url_for("boq_project_overview", pid=pid))
    with get_db() as c:
        # Delete rate-buildup rows first (FK ON DELETE CASCADE should handle
        # it too, but be explicit so older databases without FK enforcement
        # don't leak orphans).
        c.execute(
            "DELETE FROM boq_floor_rate_buildup WHERE project_id=?",
            (pid,),
        )
        c.execute(
            "DELETE FROM boq_floor_items WHERE project_id=?",
            (pid,),
        )
        c.execute(
            "UPDATE boq_projects SET updated_at=CURRENT_TIMESTAMP WHERE id=?",
            (pid,),
        )
    try:
        from new_boq_hierarchy_schema import boq_audit
        boq_audit(get_db, uid, "boq_project_reset", "boq_project", pid,
                  f"all line items cleared for {project['project_name']}")
    except Exception:
        pass
    flash(f"Project '{project['project_name']}' has been reset -- every "
          f"line item cleared. Buildings and floors are intact; pick a "
          f"template or open a section to start adding lines.", "success")
    return redirect(url_for("boq_project_overview", pid=pid))


@app.route("/boq-projects/<int:pid>/delete", methods=["POST"])
@login_required
def boq_project_delete(pid):
    """Delete the project and EVERYTHING under it (buildings, floors,
    items, rate build-up). The FOREIGN KEY ON DELETE CASCADE chain handles
    the cascade -- we delete explicitly anyway in case SQLite FK
    enforcement is off."""
    uid = session["user_id"]
    project = _boq_project_owned_or_404(pid, uid)
    csrf_protect()
    confirm = (request.form.get("confirm") or "").strip()
    if confirm != "DELETE":
        flash("Type DELETE to confirm permanent removal.", "warning")
        return redirect(url_for("boq_project_overview", pid=pid))
    name = project["project_name"]
    with get_db() as c:
        c.execute("DELETE FROM boq_floor_rate_buildup WHERE project_id=?", (pid,))
        c.execute("DELETE FROM boq_floor_items WHERE project_id=?", (pid,))
        c.execute("DELETE FROM boq_floors WHERE project_id=?", (pid,))
        c.execute("DELETE FROM boq_buildings WHERE project_id=?", (pid,))
        c.execute("DELETE FROM boq_projects WHERE id=? AND user_id=?", (pid, uid))
    try:
        from new_boq_hierarchy_schema import boq_audit
        boq_audit(get_db, uid, "boq_project_deleted", "boq_project", pid,
                  f"deleted {name}")
    except Exception:
        pass
    flash(f"Project '{name}' deleted.", "success")
    return redirect(url_for("boq_projects_list"))


# new_product_link_finder.py
# Web-crawl agent that finds Product Literature + Datasheet PDFs for
# products in equipment_catalog and saves the URLs onto the product row.
#
# Search strategy (zero-cost per the FOSS rule):
#   1. DuckDuckGo HTML endpoint (no API key needed)
#      https://html.duckduckgo.com/html/?q=...
#   2. Two queries per product:
#        <name> <brand> datasheet filetype:pdf
#        <name> <brand> brochure OR literature filetype:pdf
#   3. First non-aggregator PDF result wins.
#
# Politeness: 2-second sleep between requests, custom User-Agent that
# identifies the crawler, max 20 products per run (admin bulk mode).
#
# Schema additions (idempotent):
#   equipment_catalog.literature_url    VARCHAR(500) DEFAULT ''
#   equipment_catalog.datasheet_url     VARCHAR(500) DEFAULT ''
#   equipment_catalog.links_checked_at  TIMESTAMP                  -- when we last attempted lookup
#
# Routes:
#   POST /admin/agent/find-product-links              -- bulk, 20-product cap
#   POST /admin/agent/find-product-links/<int:pid>    -- single product
#   POST /supplier/products/<int:pid>/find-links      -- supplier self-service for their own product


# ---- Schema bootstrap (idempotent) ---------------------------------------

def _ensure_product_link_columns():
    """Add literature_url + datasheet_url + links_checked_at columns
    to equipment_catalog if not present. Works for both SQLite and
    Postgres."""
    is_pg = bool(os.environ.get("DATABASE_URL"))
    stmts_pg = [
        "ALTER TABLE equipment_catalog ADD COLUMN IF NOT EXISTS literature_url VARCHAR(500) DEFAULT ''",
        "ALTER TABLE equipment_catalog ADD COLUMN IF NOT EXISTS datasheet_url  VARCHAR(500) DEFAULT ''",
        "ALTER TABLE equipment_catalog ADD COLUMN IF NOT EXISTS links_checked_at TIMESTAMP",
    ]
    stmts_sqlite = [
        "ALTER TABLE equipment_catalog ADD COLUMN literature_url TEXT DEFAULT ''",
        "ALTER TABLE equipment_catalog ADD COLUMN datasheet_url  TEXT DEFAULT ''",
        "ALTER TABLE equipment_catalog ADD COLUMN links_checked_at TEXT",
    ]
    try:
        with get_db() as c:
            for s in (stmts_pg if is_pg else stmts_sqlite):
                try:
                    c.execute(s)
                except Exception:
                    pass
    except Exception:
        pass


# ---- Crawler ------------------------------------------------------------

_PRODUCT_LINK_UA = "SolarProBOQ/1.0 (+https://solarpro.aiappinvent.com; product-link-finder)"

# Domains we DON'T want as the "primary" datasheet/literature link --
# aggregators / search portals that don't host the actual PDF themselves.
_LINK_DENY = (
    "google.com", "duckduckgo.com", "bing.com",
    "wikipedia.org", "amazon.", "ebay.", "alibaba.",
    "youtube.com", "linkedin.com", "facebook.", "pinterest.",
    "reddit.", "quora.", "twitter.", "x.com",
)

# Brand -> preferred manufacturer doc-portal hostname(s). The crawler
# prefers a PDF on the manufacturer's own site over a reseller. Add new
# brands here as the catalogue grows.
_BRAND_DOMAINS = {
    "eaton":                 ["eaton.com"],
    "memshield":             ["eaton.com"],
    "schneider":             ["se.com", "schneider-electric.com", "schneider-electric.co.uk"],
    "abb":                   ["abb.com", "new.abb.com"],
    "siemens":               ["siemens.com", "siemens.de"],
    "philips":               ["philips.com", "lighting.philips.com", "philips.co.uk"],
    "mk":                    ["mkelectric.com", "honeywell.com"],
    "honeywell":             ["honeywell.com"],
    "hager":                 ["hager.com"],
    "hochiki":               ["hochikieurope.com", "hochiki.com"],
    "legrand":               ["legrand.com", "legrand.us"],
    "panasonic":             ["panasonic.com", "business.panasonic.com"],
    "cisco":                 ["cisco.com"],
    "juniper":               ["juniper.net"],
    "hid":                   ["hidglobal.com"],
    "hikvision":             ["hikvision.com"],
    "tropical":              ["tropical-cables.com", "tropicalcable.com"],
    "kable metal":           ["kablemetal.com"],
    "growatt":               ["growatt.com"],
    "goodwe":                ["goodwe.com"],
    "victron":               ["victronenergy.com"],
    "jinko":                 ["jinkosolar.com"],
    "ja solar":              ["jasolar.com"],
    "longi":                 ["longi.com", "en.longi.com"],
    "pylontech":             ["pylontech.com.cn"],
}


def _brand_domains(brand: str) -> list:
    """Return list of preferred manufacturer hostnames for a brand
    string. Matches partial / case-insensitive."""
    if not brand:
        return []
    bl = brand.lower()
    out = []
    for key, doms in _BRAND_DOMAINS.items():
        if key in bl or bl in key:
            for d in doms:
                if d not in out:
                    out.append(d)
    return out


def _score_url(url: str, query: str, brand_domains: list, kind: str) -> int:
    """Higher = more likely the right link. Heuristics:
      +60  hosted on the manufacturer's own domain
      +40  ends in .pdf
      +20  URL path contains 'datasheet' / 'brochure' / 'spec'
      +15  URL contains the brand name
      +10  any query word appears in URL
      -50  generic e-commerce / aggregator (already filtered by deny list)
    """
    u = (url or "").lower()
    if not u.startswith("http"):
        return 0
    if any(d in u for d in _LINK_DENY):
        return 0
    score = 0
    if any(d in u for d in (brand_domains or [])):
        score += 60
    path = u.split("?", 1)[0]
    if path.endswith(".pdf"):
        score += 40
    keywords = {
        "datasheet": ("datasheet", "data-sheet", "spec-sheet", "specsheet"),
        "literature":("brochure", "literature", "catalog", "catalogue", "product-info"),
    }
    for kw in keywords.get(kind, ()):
        if kw in u:
            score += 20
            break
    if brand_domains:
        for d in brand_domains:
            if d.split(".", 1)[0] in u:
                score += 15
                break
    for word in (query or "").lower().split():
        if len(word) >= 3 and word.isalnum() and word in u:
            score += 4
    return score


def _decode_ddg_url(href: str) -> str:
    """DuckDuckGo wraps the actual URL in /l/?uddg=encoded -- unwrap it."""
    import urllib.parse, re as _re
    if href.startswith("/l/?uddg=") or href.startswith("//duckduckgo.com/l/?") or href.startswith("https://duckduckgo.com/l/?"):
        m = _re.search(r"uddg=([^&]+)", href)
        if m:
            return urllib.parse.unquote(m.group(1))
    return href


def _search_engine(query: str, timeout: float = 9.0) -> list:
    """Return a list of candidate URLs from DuckDuckGo HTML.
    Falls back to Bing HTML if DDG returns nothing. Never raises."""
    import urllib.request, urllib.parse, re
    out = []
    headers = {"User-Agent": _PRODUCT_LINK_UA, "Accept-Language": "en-GB,en;q=0.9"}
    for engine_url in (
        "https://html.duckduckgo.com/html/?" + urllib.parse.urlencode({"q": query}),
        "https://www.bing.com/search?" + urllib.parse.urlencode({"q": query}),
    ):
        try:
            req = urllib.request.Request(engine_url, headers=headers)
            with urllib.request.urlopen(req, timeout=timeout) as r:
                html = r.read().decode("utf-8", "replace")
        except Exception:
            continue
        # DuckDuckGo result anchors
        for m in re.finditer(r'<a[^>]+class="[^"]*result__a[^"]*"[^>]+href="([^"]+)"', html):
            out.append(_decode_ddg_url(m.group(1)))
        # Bing result anchors
        for m in re.finditer(r'<h2[^>]*>\s*<a[^>]+href="([^"]+)"', html):
            out.append(m.group(1))
        if out:
            break  # got something from the first engine
    # Dedup preserving order
    seen, deduped = set(), []
    for u in out:
        u = u.strip()
        if not u or u in seen: continue
        seen.add(u); deduped.append(u)
    return deduped


def _best_match(query: str, brand_domains: list, kind: str) -> str:
    """Run the search, score every candidate, return the URL with the
    highest score (or '' if all are filtered out)."""
    candidates = _search_engine(query)
    scored = [(c, _score_url(c, query, brand_domains, kind)) for c in candidates]
    scored = [(u, s) for (u, s) in scored if s > 0]
    if not scored:
        return ""
    scored.sort(key=lambda x: x[1], reverse=True)
    return scored[0][0]


def _find_links_for(name: str, brand: str = "", model: str = "") -> tuple:
    """Return (datasheet_url, literature_url). Smart search:
      1. Try manufacturer-domain-scoped query first
      2. Fall back to a generic query
      3. Score all candidates and pick the best
    """
    import time
    base_terms = [t for t in (name, brand, model) if t]
    if not base_terms:
        return ("", "")
    brand_domains = _brand_domains(brand)
    base = " ".join(base_terms).strip()
    # Strip extremely common BOQ prose so the query is just the product name.
    for stop in ("Supply and install ", "Supply and fix ", "Supply, lay and connect ",
                 "Supply, lay and terminate ", "Wire the following points ",
                 "Wire the following point ", " as Memshield or approved equal",
                 " as Eaton or approved equal", " as Tropical or approved equal",
                 " as MK or approved equal", " as Philips or approved equal",
                 " as Hochiki or approved equal", " or approved equal"):
        base = base.replace(stop, "")
        base = base.replace(stop.strip(), "")
    base = " ".join(base.split())[:160]

    def _try(kind_word: str, kind_key: str) -> str:
        # 1. Manufacturer-domain-scoped
        for dom in brand_domains:
            q = f'{base} {kind_word} site:{dom} filetype:pdf'
            url = _best_match(q, brand_domains, kind_key)
            if url:
                return url
        # 2. Brand + kind + filetype:pdf
        q = f"{base} {kind_word} filetype:pdf"
        url = _best_match(q, brand_domains, kind_key)
        if url:
            return url
        # 3. Looser: brand + kind (any file)
        q = f"{base} {kind_word}"
        return _best_match(q, brand_domains, kind_key)

    ds = _try("datasheet", "datasheet")
    time.sleep(0.6)  # tighter to fit Render worker timeout
    lit = _try("brochure OR literature", "literature")
    return (ds, lit)


